body.script:
/* ============================================================
   DOUGHBOROUGH ENGINE v6 — portable calculation core
   Explicit inputs, pizza + bread styles, separate room/cold timing models.
   ============================================================ */

const STYLES = {
  neapolitan:{name:"Neapolitan",category:"pizza",shape:"round",density:2.39,defaultQty:2,defaultSize:12,hydration:58,salt:2.5,oil:0,sugar:0,milkPowder:0,
    bake:{min:400,max:450,idealMin:425},times:{easy:10,poolish:12,biga:20},ranges:{easy:[8,12],poolish:[10,14],biga:[18,22]},
    shapeStep:"Stretch each ball by hand from the centre outward, moving gas toward the rim instead of pressing it out. Do not flatten the rim; that rim becomes the puffy, blistered cornicione.",
    description:"Neapolitan pizza is a small, very thin pizza with a soft centre and a large, puffy, blistered rim. It works best with minimal toppings and very high heat."},
  ny:{name:"New York",category:"pizza",shape:"round",density:2.7,defaultQty:2,defaultSize:16,hydration:62,salt:2.5,oil:2,sugar:1,milkPowder:0,
    bake:{min:325,max:375,idealMin:350},times:{easy:8,poolish:14,biga:20},ranges:{easy:[6,12],poolish:[10,18],biga:[16,28]},
    shapeStep:"Stretch each ball into an even, flat round with a low border. A rolling pin can be used lightly for a flatter, more uniform base.",
    description:"New York pizza is large and thin with a low border, a crisp underside, flexible slice and chewy bite. It tolerates moderate sauce and cheese but still benefits from restrained toppings."},
  detroit:{name:"Detroit",category:"pizza",shape:"rectangle",density:6.0,defaultQty:1,defaultLength:12,defaultWidth:8,hydration:65,salt:2.8,oil:2,sugar:0,milkPowder:0,
    bake:{min:225,max:275,idealMin:250},times:{easy:6,poolish:12,biga:20},ranges:{easy:[4,10],poolish:[8,16],biga:[16,28]},
    shapeStep:"Press the dough into a well-oiled rectangular pan, pushing it toward the edges and corners. Cheese can go right to the edge so it fries into the crust.",
    description:"Detroit pizza is a thick rectangular pan pizza with a light interior, crisp fried base and caramelised cheese edges."},
  focaccia:{name:"Focaccia",category:"bread",shape:"rectangle",density:6.0,defaultQty:1,defaultLength:13,defaultWidth:9,hydration:80,salt:3.0,oil:5,sugar:0,milkPowder:0,
    hasDepth:true,defaultDepth:1.5,depthMin:1,depthMax:2,depthK:4,bake:{min:200,max:250,idealMin:225},times:{easy:8,poolish:14,biga:20},ranges:{easy:[5,14],poolish:[10,20],biga:[16,30]},
    shapeStep:"Spread the dough into a well-oiled pan, rest if it resists, then dimple deeply with your fingertips.",
    description:"Focaccia is an oil-rich flatbread with a dimpled surface, open crumb, crisp golden exterior and moist interior."},
  roman:{name:"Roman al Taglio",category:"pizza",shape:"rectangle",density:5.2,defaultQty:1,defaultLength:12,defaultWidth:8,hydration:75,salt:2.5,oil:3,sugar:0.5,milkPowder:0,
    bake:{min:230,max:290,idealMin:250},times:{easy:10,poolish:16,biga:22},ranges:{easy:[6,14],poolish:[12,22],biga:[18,32]},
    shapeStep:"Ease the dough into an oiled tray without crushing the gas. Rest whenever it resists, then press gently to the corners.",
    description:"Roman al taglio is a high-hydration tray pizza with an airy crumb and a crisp base. It is cut into rectangular pieces and often benefits from a staged bake."},
  ciabatta:{name:"Ciabatta",category:"bread",shape:"rectangle",sizing:"weight",defaultWeight:400,defaultQty:2,hydration:78,salt:2.2,oil:0,sugar:0,milkPowder:0,
    bake:{min:220,max:250,idealMin:235},times:{easy:10,poolish:16,biga:22},ranges:{easy:[6,14],poolish:[12,22],biga:[18,32]},
    shapeStep:"Handle the dough gently, divide with a scraper and stretch each piece into a rough slipper shape without tightening or degassing it.",
    description:"Ciabatta is a high-hydration lean bread with an open, irregular crumb, thin crisp crust and chewy texture. Gentle handling preserves its internal air."},
  softbread:{name:"Soft White Bread",category:"bread",shape:"rectangle",sizing:"weight",defaultWeight:850,formatWeights:{loaf:850,rolls:70},defaultQty:1,hydration:64,salt:2.0,oil:6,sugar:6,milkPowder:4,
    bake:{min:180,max:205,idealMin:190},times:{easy:5,poolish:11,biga:18},ranges:{easy:[3,8],poolish:[8,16],biga:[14,26]},
    shapeStep:"Shape firmly enough to create an even skin, then proof until soft, puffy and close to its final baked size.",
    description:"One soft enriched dough for either a sandwich loaf or dinner rolls. The formula stays the same; portioning, proofing and bake time change with the format."},
  baguette:{name:"Baguette",category:"bread",shape:"rectangle",sizing:"weight",defaultWeight:350,defaultQty:2,hydration:68,salt:2.2,oil:0,sugar:0,milkPowder:0,
    bake:{min:225,max:260,idealMin:240},times:{easy:10,poolish:16,biga:22},ranges:{easy:[6,14],poolish:[12,22],biga:[18,32]},
    shapeStep:"Pre-shape gently, rest, then roll each piece into a taut cylinder without crushing the internal gas. Score immediately before baking.",
    description:"Baguette is a lean crusty bread with a thin crisp shell, open cream-coloured crumb and elongated shape. Shaping, scoring and steam are central to the result."}
};
const STYLE_ORDER=["neapolitan","ny","detroit","roman","focaccia","ciabatta","baguette","softbread"];
const STYLE_STAGE_PROFILE={
  neapolitan:{directBulk:0.25,prefermentBulk:0.25},
  ny:{directBulk:0.60,prefermentBulk:0.55},
  detroit:{directBulk:0.42,prefermentBulk:0.40},
  roman:{directBulk:0.62,prefermentBulk:0.58},
  focaccia:{directBulk:0.55,prefermentBulk:0.50},
  ciabatta:{directBulk:0.76,prefermentBulk:0.72},
  baguette:{directBulk:0.72,prefermentBulk:0.68},
  softbread:{directBulk:0.64,prefermentBulk:0.60}
};
const STYLE_DEFAULT_PROTEIN={neapolitan:12.5,ny:12.0,detroit:12.0,roman:12.5,focaccia:12.5,ciabatta:12.5,baguette:12.5,softbread:11.5};
function roundQuarter(h){return Math.round(Number(h)*4)/4;}
function splitFinalStages(totalH,styleKey,isTrad){
  const total=Math.max(0.5,Number(totalH)||0.5);
  const profile=STYLE_STAGE_PROFILE[styleKey]||STYLE_STAGE_PROFILE.ny;
  const share=isTrad?profile.prefermentBulk:profile.directBulk;
  let bulk=roundQuarter(total*share), proof=roundQuarter(total-bulk);
  const minStage=total<2?0.25:0.5;
  bulk=Math.max(minStage,bulk); proof=Math.max(minStage,roundQuarter(total-bulk));
  const drift=roundQuarter(total-bulk-proof); proof=roundQuarter(proof+drift);
  if(proof inches
function lenFromBase(inch){return UNIT.len==='cm'? inch/IN_PER_CM : inch;}            // inches -> display
function fmtLenNum(inch){const v=lenFromBase(inch);return UNIT.len==='cm'?Math.round(v*100)/100:Math.round(v*10)/10;}
function lenLabel(){return UNIT.len;}
function tempToBase(v){const n=Number(v); return UNIT.temp==='F'? (n-32)*5/9 : n;}    // display -> °C
function tempFromBase(c){return UNIT.temp==='F'? c*9/5+32 : c;}                       // °C -> display
function tF(c){return Math.round(tempFromBase(Number(c)))+'°'+UNIT.temp;}             // °C -> "250°C"/"482°F"
function tempLabel(){return '°'+UNIT.temp;}
function wtFromBase(g){return UNIT.wt==='oz'? g/G_PER_OZ : g;}                         // grams -> display
function wtToBase(v){const n=Number(v); return UNIT.wt==='oz'? n*G_PER_OZ : n;}        // display -> grams
function wNum(g){const v=wtFromBase(Number(g)); if(UNIT.wt==='oz')return Math.round(v*100)/100; return Math.round(v);}
// yeast is small — always show one decimal so 1.2 g doesn't collapse to 1 g
function wNumY(g){const v=wtFromBase(Number(g));if(UNIT.wt==='oz')return Math.round(v*10000)/10000;if(v>0&&v<1)return Math.round(v*100)/100;return Math.round(v*10)/10;}
function gWy(g){return wNumY(g)+UNIT.wt;}
function gW(g){return wNum(g)+UNIT.wt;}                                               // "315g"/"11.1oz"
function wtLabel(){return UNIT.wt;}

/* ===== SCHEDULING ENGINE — turns relative stage hours into wall-clock times ===== */
let schedMode='none';   // 'none' | 'startNow' | 'startAt' | 'readyBy'
let schedAnchor=null;   // ms epoch for startAt / readyBy


const OVEN_TYPES={home:{name:"home oven",typicalMax:275},pizza:{name:"pizza oven",typicalMax:450}};
const BASES={dual:{name:"two surfaces",timeFactor:0.82},steel:{name:"a pizza steel",timeFactor:0.9},stone:{name:"a pizza stone",timeFactor:1.0},tray:{name:"a baking tray",timeFactor:1.18}};
const THIN_STYLES=["neapolitan","ny"], PAN_STYLES=["detroit","focaccia","roman","softbread"], LEAN_BREAD_STYLES=["ciabatta","baguette"];
function estimateCookSeconds(styleKey,ovenTemp,base,breadFormat="loaf"){
  const t=Number(ovenTemp);
  const map={
    neapolitan:{lowT:375,lowS:150,highT:450,highS:60},ny:{lowT:300,lowS:420,highT:375,highS:120},
    detroit:{lowT:225,lowS:900,highT:275,highS:600},focaccia:{lowT:200,lowS:1500,highT:240,highS:900},
    roman:{lowT:230,lowS:1080,highT:290,highS:600},ciabatta:{lowT:220,lowS:1800,highT:250,highS:1200},
    softbread:{lowT:180,lowS:2100,highT:205,highS:1500},baguette:{lowT:225,lowS:1800,highT:260,highS:1080}
  };
  let m=map[styleKey]; if(!m)return 1200;
  if(styleKey==="softbread"&&breadFormat==="rolls")m={lowT:180,lowS:1200,highT:205,highS:720};
  let secs;
  if(t=m.highT)secs=m.highS;
  else secs=m.lowS+(m.highS-m.lowS)*((t-m.lowT)/(m.highT-m.lowT));
  if(base&&BASES[base]&&!PAN_STYLES.includes(styleKey))secs*=BASES[base].timeFactor;
  return Math.max(30,secs);
}
function cookTime(styleKey,ovenTemp,base,breadFormat="loaf"){return fmtDuration(estimateCookSeconds(styleKey,ovenTemp,base,breadFormat));}
// bake guidance: encodes the oven-type × surface × style hierarchy
function bakeGuidance(styleKey,ovenType,base){
  const thin=THIN_STYLES.includes(styleKey), pan=PAN_STYLES.includes(styleKey);
  const g={ovenNote:"",baseNote:"",warn:null,setup:null,suitability:""};
  g.ovenNote = ovenType==="pizza"
    ? "Pizza ovens run hot (400 °C+) and suit thin styles. Their low, fierce ceiling scorches focaccia and struggles with thick pan bakes."
    : "Home ovens suit pan pizza and bread, and can handle thin pizza well with a fully preheated steel or stone.";
  if(LEAN_BREAD_STYLES.includes(styleKey)){
    g.baseNote = base==="tray" ? "A heavy tray works; parchment makes loading easier. A stone or steel gives stronger bottom heat." : "Preheat the surface fully. Load on parchment if handling the shaped loaf directly is difficult.";
    g.suitability = ovenType==="pizza" ? "A low-domed pizza oven is difficult to manage for long bread bakes; a conventional home oven is easier and more even." : "A conventional oven is well suited to this bread. Add steam early, then vent it so the crust can dry.";
    if(ovenType==="pizza") g.warn="Bread needs a longer, more even bake than a typical pizza oven is designed to provide. Watch the top closely or use a conventional oven.";
    return g;
  }
  if(pan){
    g.baseNote=styleKey==="softbread"?"Bake the loaf in its tin, or rolls on a tray. A stone or steel underneath is unnecessary.":"This style bakes in its pan, so the surface choice does not materially change the method.";
    g.suitability = ovenType==="pizza"
      ? "A pizza oven isn't the tool for this — its low, hot ceiling burns the top before the middle bakes. Use a home oven."
      : "A home oven is ideal for this style — no special surface needed.";
    if(ovenType==="pizza") g.warn="A pizza oven's low ceiling scorches the top of a thick bake before it cooks through. A home oven is the right tool here.";
    return g;
  }
  // thin styles
  g.suitability = ovenType==="pizza"
    ? "A pizza oven is ideal for this style."
    : "Workable in a home oven with a steel or stone, but it won't match a pizza oven — expect a longer bake and a less blistered crust.";
  if(base==="steel"){
    g.baseNote="Steel holds the most heat and gives the fastest, most aggressive base.";
    if(ovenType==="pizza") g.warn="A pizza steel gets hotter than a stone and will burn the base in a pizza oven. Use a stone instead.";
  } else if(base==="stone"){
    g.baseNote="A stone is porous and can accept some moisture from the base. Steel cannot absorb moisture, but transfers heat much faster and browns more aggressively. Stone is the safer surface in a pizza oven.";
  } else if(base==="tray"){
    g.baseNote="A tray is the last resort — it softens the base. If you have a steel or stone, use it instead.";
    g.warn="A baking tray softens the base of a thin pizza. Use a preheated steel or stone if you have one.";
  } else if(base==="dual"){
    g.baseNote="The best home-oven setup for thin pizza: top and bottom heat at once.";
    if(ovenType==="home"){
      g.setup="Two steels is ideal — one as the base, one above. With a steel and a stone, put the stone on the bottom as the base and the steel on top: steel radiates far more heat downward than stone, and the top is where you need it. Two racks in the top two slots, as close together as they go; preheat to max on full fan-forced (not the pizza setting), wait 30 minutes after it hits temperature, then launch onto the lower surface — the upper one grills the top.";
    } else {
      g.setup="In a pizza oven you don't need this — a single stone is enough, and the hot ceiling already sets the top. Switch to a stone.";
    }
  }
  return g;
}
function fmtDuration(secs){
  if(secs<90)return Math.round(secs/5)*5+" seconds";
  if(secs<180)return "1–2 minutes";
  const m=secs/60,lo=Math.floor(m*0.85),hi=Math.ceil(m*1.15);
  return lo===hi?lo+" minutes":lo+"–"+hi+" minutes";
}

const PREFERMENT_PROFILES={
  biga:{name:"Biga",flourPct:100,hydration:50,maturityExposure:{min:12,max:24,target:16},maturityLoad:{min:1.6,max:3.2,target:2.4}},
  poolish:{name:"Poolish",flourPct:30,hydration:100,maturityExposure:{min:4,max:8,target:6},maturityLoad:{min:1.6,max:3.2,target:2.4}}
};
/* Compatibility alias used by the UI. minHours/maxHours are the 25°C reference windows. */
const PREFERMENTS=Object.fromEntries(Object.entries(PREFERMENT_PROFILES).map(([k,p])=>[k,{...p,minHours:p.maturityExposure.min,maxHours:p.maturityExposure.max}]));
const YEAST={instant:{name:"Instant dry",factor:1},active:{name:"Active dry",factor:1.25},fresh:{name:"Fresh",factor:3}};
const DEFAULT_TOTAL={easy:6,trad:18};
const PREFERMENT_DEFAULT_TOTAL={poolish:12,biga:20};
const TIME_LIMITS={easy:{min:1,max:12},poolish:{min:7,max:16},biga:{min:15,max:32}};
const NEAPOLITAN_TIME_PRESETS={
  easy:{defaultTotal:10,range:{min:8,max:12},bulk:2,ball:8},
  poolish:{defaultTotal:12,range:{min:10,max:14},preferment:7,bulk:1,ball:4},
  biga:{defaultTotal:20,range:{min:18,max:22},preferment:16,bulk:1,ball:3}
};
const ASAP_TOTALS={neapolitan:4,ny:4,detroit:4,roman:5,focaccia:4,ciabatta:4,baguette:4,softbread:3};
/*
  Named cold options are duration constraints selected by the user, not a second
  biological timing model. The same exposure engine still calculates yeast,
  cooling contribution and warnings from the chosen duration.
*/
const COLD_DURATION_PRESETS={
  asap:{central:12,min:10,max:16,label:"short cold plan"},
  sameday:{central:18,min:14,max:24,label:"same-day cold plan"},
  nextday:{central:24,min:18,max:30,label:"next-day cold plan"},
  "2-3day":{central:48,min:36,max:72,label:"two-to-three-day cold plan"}
};
const COLD_STAGE_PROFILE={
  neapolitan:{before:0.5,after:3},ny:{before:0.5,after:3},detroit:{before:0.5,after:2},roman:{before:0.5,after:2},
  focaccia:{before:0.5,after:2},ciabatta:{before:0.5,after:1.5},baguette:{before:0.5,after:1.5},softbread:{before:0.5,after:2}
};

function timePreset(styleKey,methodKey,prefermentKey){
  if(styleKey==="neapolitan"){
    const k=methodKey==="easy"?"easy":prefermentKey;
    return NEAPOLITAN_TIME_PRESETS[k]||null;
  }
  return null;
}
function getDefaultTotalFor(styleKey,methodKey,prefermentKey){
  const preset=timePreset(styleKey,methodKey,prefermentKey);
  if(preset)return preset.defaultTotal;
  const s=STYLES[styleKey];
  if(s&&s.times){const k=methodKey==="easy"?"easy":prefermentKey;if(s.times[k]!=null)return s.times[k];}
  if(methodKey==="easy")return DEFAULT_TOTAL.easy;
  return PREFERMENT_DEFAULT_TOTAL[prefermentKey]||DEFAULT_TOTAL.trad;
}
function getRecommendedRange(styleKey,methodKey,prefermentKey){
  const preset=timePreset(styleKey,methodKey,prefermentKey);
  if(preset)return preset.range;
  const s=STYLES[styleKey],k=methodKey==="easy"?"easy":prefermentKey;
  if(s&&s.ranges&&s.ranges[k])return {min:s.ranges[k][0],max:s.ranges[k][1]};
  return TIME_LIMITS[k];
}

function num(v,f){return v===undefined||v===null||v===""||isNaN(Number(v))?f:Number(v);}
const AMBIENT_BASELINE_C=25;
const FERMENT_ACTIVITY_POINTS=[
  {c:1,rate:0.035},{c:4,rate:0.10},{c:6,rate:0.14},{c:8,rate:0.21},{c:10,rate:0.30},
  {c:15,rate:0.50},{c:20,rate:0.71},{c:25,rate:1.00},{c:30,rate:1.41},{c:35,rate:1.65}
];
/*
  Relative baker's-yeast activity model, anchored to 25°C = 1.0.
  - 15–30°C follows the familiar Q10≈2 shape closely.
  - 1–<10°C uses a steeper, deliberately lower cold curve; 10–15°C is a supported cool-room transition band.
  - Above 35°C automatic timing is marked unsupported rather than extrapolated toward zero.
  The uncertainty band is part of the result and is shown to the user as a time range.
*/
function fermentationActivity(tempC){
  const c=num(tempC,AMBIENT_BASELINE_C);
  let supported=true,regime="room",message="";
  if(c<1){supported=false;regime="cold";message="Below 1°C the dough is near-freezing and this calculator cannot predict fermentation reliably.";}
  else if(c<10)regime="cold";
  else if(c<15)regime="transition";
  else if(c<=30)regime="room";
  else if(c<=35){regime="hot";message="Fermentation is fast and increasingly difficult to control above 30°C.";}
  else{supported=false;regime="hot";message="Above 35°C the model is not reliable: yeast output no longer follows a simple acceleration curve and dough quality can deteriorate quickly.";}
  const cc=Math.max(1,Math.min(35,c));
  let rate=FERMENT_ACTIVITY_POINTS[0].rate;
  for(let i=0;i=a.c&&cc<=b.c){const f=(cc-a.c)/(b.c-a.c);rate=Math.exp(Math.log(a.rate)+(Math.log(b.rate)-Math.log(a.rate))*f);break;}
  }
  const u=regime==="cold"?0.30:regime==="transition"?0.22:regime==="room"?0.15:0.25;
  return {c,rate,low:Math.max(0.005,rate*(1-u)),high:rate*(1+u),uncertainty:u,supported,regime,message};
}
function exposureFor(hours,tempC){return Math.max(0,num(hours,0))*fermentationActivity(tempC).rate;}
function durationRangeForExposure(minExposure,maxExposure,tempC){const p=fermentationActivity(tempC);return {min:Math.max(0,minExposure/p.high),max:Math.max(0,maxExposure/p.low)};}
/*
  Refrigerated dough does not instantly become refrigerator-cold. The centre cools
  over several hours, and the early part of the cold hold therefore ferments faster
  than a simple "hours × fridge rate" model predicts. This function integrates a
  conservative exponential cooling curve and carries a deliberately wide band.
*/
function coolingHoursForMass(doughMassG){
  const g=Math.max(100,num(doughMassG,500));
  return Math.max(2,Math.min(6,2.5+0.9*Math.log2(g/250)));
}
function coldStageExposure(hours,roomTemp,fridgeTemp,doughMassG=500){
  const h=Math.max(0,num(hours,0)),cooling=Math.min(h,coolingHoursForMass(doughMassG));
  if(h<=0)return {central:0,low:0,high:0,coolingHours:0};
  const steps=Math.max(8,Math.ceil(cooling*8)),dt=cooling/steps;
  let central=0,low=0,high=0;
  for(let i=0;i<steps;i++){
    const t=(i+0.5)*dt;
    // Three time constants brings the centre close to the refrigerator temperature.
    const c=fridgeTemp+(roomTemp-fridgeTemp)*Math.exp(-3*t/Math.max(0.25,cooling));
    const a=fermentationActivity(c);central+=a.rate*dt;low+=a.low*dt;high+=a.high*dt;
  }
  const hold=Math.max(0,h-cooling),fa=fermentationActivity(fridgeTemp);
  central+=hold*fa.rate;low+=hold*fa.low;high+=hold*fa.high;
  return {central,low,high,coolingHours:cooling};
}
function coldDurationForExposure(target,roomTemp,fridgeTemp,doughMassG=500,band='central'){
  const goal=Math.max(0,num(target,0));if(goal<=0)return 0;
  let lo=0,hi=240;
  for(let i=0;i<42;i++){const mid=(lo+hi)/2,v=coldStageExposure(mid,roomTemp,fridgeTemp,doughMassG)[band];if(v<goal)lo=mid;else hi=mid;}
  return roundQuarter((lo+hi)/2);
}
function timeRangeAround(value,fraction=0.2,min=0){const v=Math.max(min,num(value,min));return [Math.max(min,roundQuarter(v*(1-fraction))),Math.max(min,roundQuarter(v*(1+fraction)))];}
function stageObj(rec,val,range,cue=""){return {rec:r2(rec),val:r2(val),range:[r2(range[0]),r2(range[1])],cue};}
function fmtHRange(range){if(!range)return"";const a=Array.isArray(range)?range[0]:range.min,b=Array.isArray(range)?range[1]:range.max;return Math.abs(a-b)<0.01?fmtH(a):`${fmtH(a)}–${fmtH(b)}`;}
function recommendedTotalPlan(styleKey,methodKey,prefermentKey,ambientC,fermentationMode="room",timeframe=null,fridgeC=4,doughMassG=500){
  if(fermentationMode==="cold"){
    const room=fermentationActivity(ambientC),fridge=fermentationActivity(fridgeC);
    const pf=PREFERMENT_PROFILES[prefermentKey]||PREFERMENT_PROFILES.poolish;
    const prefRange=methodKey==="trad"?durationRangeForExposure(pf.maturityExposure.min,pf.maturityExposure.max,ambientC):{min:0,max:0};
    const prefCentral=methodKey==="trad"?roundQuarter(pf.maturityExposure.target/room.rate):0;
    const preset=timeframe?COLD_DURATION_PRESETS[timeframe]:null;

    if(preset){
      // Fixed-duration mode: the user has chosen the available window. Exposure
      // from that window is still calculated by the same cold-stage model and is
      // later used to solve the yeast dose. The preset is not a competing rate curve.
      const finalDough={central:roundQuarter(preset.central),min:roundQuarter(preset.min),max:roundQuarter(preset.max)};
      const exposure={
        central:r2(defaultColdFinalExposure(finalDough.central,ambientC,fridgeC,doughMassG,styleKey)),
        min:r2(defaultColdFinalExposure(finalDough.min,ambientC,fridgeC,doughMassG,styleKey)),
        max:r2(defaultColdFinalExposure(finalDough.max,ambientC,fridgeC,doughMassG,styleKey))
      };
      return {
        central:roundQuarter(finalDough.central+prefCentral),
        min:roundQuarter(finalDough.min+(methodKey==="trad"?prefRange.min:0)),
        max:roundQuarter(finalDough.max+(methodKey==="trad"?prefRange.max:0)),
        finalDough,exposure,constraint:"fixed-duration",source:"cold-duration-preset"+(methodKey==="trad"?"+preferment":""),
        supported:room.supported&&fridge.supported
      };
    }

    // Exposure-target mode: no duration was imposed, so solve the refrigerator
    // hold from the style's maturity target and range using the same activity curve.
