    fermentationMode,isCold,roomTemp,coldTemp,timeRange,ovenType:opts.ovenType||"home",bakeBase:opts.bakeBase||"steel",coolingHours:isCold?r1(coldExposure.coolingHours):0,stageAmounts:{flour:{preferment:r0(stageFlour.preferment),final:r0(stageFlour.final)},water:{preferment:r0(stageWater.preferment),final:r0(stageWater.final)},finalYeast:r1(mainYeastG)}};
  return {styleKey,styleName:base.name,methodKey,methodName:isTrad?"Preferment":"Direct",shape:shp,size:sz,quantity:qty,breadFormat,percentages:p,yeastType,yeastTypeName:YEAST[yeastType].name,isTrad,preferment:prefermentObj,poolishStyle,
    fermentationMode,isCold,roomTemp,coldTemp,temperatureModel:{room:roomActivity,cold:isCold?coldActivity:null,cooling:isCold?coldExposure:null},timeRange,totalHours:total,totalTime,stages,exposure:{final:r2(finalExposure),preferment:isTrad?r2(prefSpec.maturity.exposure):0},
    loss:{rec:recLoss,val:r1(lossPct),netDough:r0(netDough)},vinegar:{on:vinegarActive,pct:r1(vinegarPct),rec:recVinegar,grams:r1(vinegarG),protein:num(flourProtein,12)},
    water:{tempC:waterTempC,rawTempC:r1(rawWaterTemp),predictedDoughTemp:r1(predictedDoughTemp),cue:waterCue,ddt:ddtTarget,hotMachine,status:waterStatus,feasible:waterStatus==="feasible",message:waterMessage,limited:waterStatus!=="feasible"},
    bakeInfo:{base:opts.bakeBase||"steel",ovenType:opts.ovenType||"home",timeStr:fmtDuration(bakeSeconds),seconds:bakeSeconds,tempC:ovenTempC},ambient:{c:roomTemp,factor:r2(1/roomActivity.rate),activity:r2(roomActivity.rate)},
    mainYeastPct:r2(mainYeastPct),mainYeastRec:r2(mainYeastRec),mainYeastRange:mainYeastRange.map(r2),totalYeastPct:r2(totalYeastPct),pctTable,totals:{doughWeight:r0(netDough),grossDough:r0(totalDough),lossGrams:r0(totalDough-netDough),ballWeight:r0(perBall),ballWeightRec:r0(recPerBall),...ingredients},
    ingredients,yeastTotals:{preferment:r1(prefermentYeastG),final:r1(mainYeastG),total:r1(mainYeastG+prefermentYeastG)},stageAmounts:{flour:{preferment:r0(stageFlour.preferment),final:r0(stageFlour.final)},water:{preferment:r0(stageWater.preferment),final:r0(stageWater.final)},finalYeast:r1(mainYeastG),prefermentYeast:r1(prefermentYeastG)},
