  const s=[];const hasOil=p.oil>0,hasSugar=p.sugar>0;
  const durH=[];const add=(t,d)=>{s.push(t);durH.push(d||0);};
  const _ing=ingredients||{};const _doughG=Object.keys(_ing).reduce((a,k)=>a+(typeof _ing[k]==="number"?_ing[k]:0),0)||540;
  const bufF=1+Math.min(2,Math.max(0,(_doughG-540)/1080));const mins=m=>Math.round(m*bufF)/60;
  const _schedOn=(typeof schedMode!=="undefined"&&schedMode!=="none");
  function _stepClock(ms,startMs){const d=new Date(Math.round(ms/300000)*300000);let h=d.getHours();const ap=h<12?"am":"pm";let hh=h%12||12;const str=hh+":"+String(d.getMinutes()).padStart(2,"0")+ap;return d.toDateString()!==new Date(startMs).toDateString()?d.toLocaleDateString([],{weekday:"short"})+" "+str:str;}
  function finish(){if(_schedOn){const H=3600000,total=durH.reduce((a,b)=>a+b,0)*H,a=(typeof schedAnchor!=="undefined"&&schedAnchor)?schedAnchor:Date.now();let t=schedMode==="startNow"?Date.now():schedMode==="startAt"?a:a-total;const start=t;for(let i=0;i=72,lowHydration=p.hydration<=62;
  const isPanStyle=PAN_STYLES.includes(styleKey),isDetroit=styleKey==="detroit",isFocaccia=styleKey==="focaccia",isRoman=styleKey==="roman",isCiabatta=styleKey==="ciabatta",isBaguette=styleKey==="baguette",isSoftBread=styleKey==="softbread";
  const ballWord=quantity===1?"ball":"balls",panWord=quantity===1?"pan":"pans",portionWord=quantity===1?"portion":"portions";
  const why=txt=>expanded?" "+txt:"";
  const I=ingredients||{};

  function waterTempStr(){return waterTempC==null?"":` at about ${tF(waterTempC)} (${waterCue})`;}
  function seasoningStr(includeOil=true){
