    if(light)return `During the early bulk, give the dough ${sets} gentle ${setWord} of stretch-and-folds, spaced about 30 minutes apart where the available time allows, then leave it undisturbed.`;
    return `During the early bulk, give the dough ${sets} ${setWord} of stretch-and-folds, spaced about 30 minutes apart where the available time allows: with a wet hand, lift one side, stretch it without tearing and fold it over; turn the bowl and repeat around the dough.`;
  }
  function yeastWaterInstruction(yeastG,totalWaterG,context="dough"){
