    if(yeastType==="active")return `Rehydrate the ${y} active dry yeast for 10–15 minutes in a small portion of the measured water at about ${tF(36)}, then combine it with the remaining measured water${temp}. Keep the total water at ${w}.`;
    return `Crumble the ${y} fresh yeast into the ${w} water${temp} and stir until dispersed.`;
  }
  function developmentStep(label="dough"){
    if(isSoftBread){
      const oilStage=hasOil?` Knead for 3–4 minutes until the ${label} begins to strengthen, then add the ${gW(I.oil)} oil gradually and continue kneading.`:"";
      add(`${hasOil?oilStage.trim():"Knead the "+label+"."} Continue ${byHand?"by hand for a total of about 8–12 minutes":"on low to medium-low speed for a total of about 7–10 minutes"}, until smooth, elastic and able to stretch into a thin membrane.`+why("Soft enriched dough needs substantial gluten development because sugar and fat soften and slow the network. Adding the oil after the dough has begun to strengthen makes development easier."),mins(byHand?12:10));
    }else if(byHand&&highHydration){
