    if(isCiabatta)return `Transfer the ciabatta gently to the hot surface and create steam using the prepared metal tray or covered setup. Bake at ${tF(ovenTemp)} for about ${cookTimeStr}, until deeply coloured and light for its size. Vent for the final third, then cool completely on a rack before cutting.`;
    if(isSoftBread){const target=breadFormat==="rolls"?"evenly golden and about 88–92°C inside":"evenly golden and about 88–93°C inside",product=breadFormat==="rolls"?(quantity===1?"roll":"rolls"):(quantity===1?"loaf":"loaves");return `Bake at ${tF(ovenTemp)} for about ${cookTimeStr}, until ${target}. Turn the ${product} out promptly and cool on a rack; brush with butter after baking only if a softer crust is wanted.`;}
    if(isRoman)return `Bake at ${tF(ovenTemp)} for about ${cookTimeStr}. For wet or delicate toppings, bake the lightly topped or untopped base until it has set, add those toppings, then finish until the underside is crisp and the crumb is cooked through. After a short rest, move it from the tray to a rack so the base does not steam-soften.`;
    if(isDetroit)return `Bake at ${tF(ovenTemp)} for about ${cookTimeStr}, until the cheese edge is deeply caramelised, the underside is crisp and the centre is cooked through. Rest briefly, then release the edges and lift from the pan so trapped steam does not soften the base.`;
    if(isFocaccia)return `Bake at ${tF(ovenTemp)} for about ${cookTimeStr}, until deeply golden on top and underneath. Remove from the pan after a short rest and cool on a rack so the base stays crisp.`;
    let txt=`Bake at ${tF(ovenTemp)} for about ${cookTimeStr}, until the base is set and the crust is properly coloured.`;
    if((styleKey==="neapolitan"||styleKey==="ny")&&Number(ovenTemp)0.04,finalYeastText=hasFinalYeast?`${gWy(finalYeast)} finishing yeast`:"";
  let elapsedH=0;
  if(isBiga){
    add(`Make the biga. ${yeastWaterInstruction(pf.yeast,pf.water,"biga")} Add the ${gW(pf.flour)} flour. Squeeze and toss only until all flour is moistened and the mixture forms stiff, irregular clumps; do not knead it smooth.`+why("A biga is intentionally stiff and discontinuous. A smooth, fully kneaded dough would ferment and develop differently."),mins(yeastType==="active"?20:15));
  }else{
    add(`Make the poolish. ${yeastWaterInstruction(pf.yeast,pf.water,"poolish")} Stir in the ${gW(pf.flour)} flour until no dry pockets remain and the batter is evenly mixed.`,mins(yeastType==="active"?18:10));
  }
  elapsedH+=pf.hours;
  const maturityCue=isBiga
    ? `expanded and aerated inside, with a domed or lightly cracked surface and a clean sweet, wheaty aroma—not collapsed, wet or sharply alcoholic`
    : `well expanded and full of bubbles, with the surface at peak or just beginning to level—not fully collapsed or sharply alcoholic`;
  add(`Cover and ferment the ${pf.name.toLowerCase()} at about ${tF(roomTemp)} for ${fmtHRange(pf.timeRange)}, using it when it is ${maturityCue}.`+((expanded&&!_schedOn)?elapsed(elapsedH):"")+why("The visible maturity cue is the final decision because flour, container shape and yeast condition shift the exact clock time."),pf.hours);

  const pname=pf.name.toLowerCase();
  if(isBiga){
    const flourStep=remFlour>0?` Add the remaining ${gW(remFlour)} flour and the ${seasoningStr(false)}`:` Add the ${seasoningStr(false)}; all of the flour is already in the biga`;
    add(`Tear the mature biga into small pieces. Add most of the remaining ${gW(remWater)} water${waterTempStr()}${hasFinalYeast?`, with the ${finalYeastText} dissolved in it`:""}, and squeeze or mix until the pieces begin to disperse.${flourStep}. Hold back only a small part of the measured water at first, then add all of it gradually as the dough comes together.`+why("Breaking the stiff biga up before full mixing prevents dry flour knots from surviving inside the finished dough. All measured water still belongs in the formula; holding some back only controls incorporation."),mins(12));
  }else if(remFlour<=0){
    add(`Loosen the poolish gradually with the remaining ${gW(remWater)} water${waterTempStr()}${hasFinalYeast?`, with the ${finalYeastText} dissolved in it`:""}. Add the ${seasoningStr(false)} and mix to a cohesive dough; all of the flour is already in the poolish.`,mins(8));
  }else if(poolishStyle==="stiff"){
    add(`Mix the remaining ${gW(remFlour)} flour and the ${seasoningStr(false)} into the poolish, using enough of the remaining ${gW(remWater)} water to form a firm dough. Reserve the rest of the water${hasFinalYeast?`, dissolving the ${finalYeastText} in it`:""}, then add it gradually until fully absorbed.`+why("The firm-first sequence builds a tighter dough before the remaining water is incorporated. Add the water in stages to avoid lumps or a flooded dough."),mins(14));
  }else{
    add(`Loosen the poolish with the remaining ${gW(remWater)} water${waterTempStr()}${hasFinalYeast?`, with the ${finalYeastText} dissolved in it`:""}. Add the remaining ${gW(remFlour)} flour and the ${seasoningStr(false)}, then mix until no dry flour remains.`+why("The wet-first sequence disperses the poolish evenly and generally produces the softer, more extensible finish."),mins(10));
  }
