    add(`Cover and rest the completed dough at about ${tF(roomTemp)} for ${fmtHRange(stages.bulk.range)}, until it begins to relax and aerate.${fold}`+((expanded&&!_schedOn)?elapsed(elapsedH):""),stages.bulk.val);
