  else add(`Cover and bulk ferment for ${fmtHRange(stages.bulk.range)} at about ${tF(roomTemp)}, until the completed dough has regained strength and begun to aerate.`+((expanded&&!_schedOn)?elapsed(elapsedH):""),stages.bulk.val);
