function fmtH(h){
  if(h==null)return"";h=Number(h);const totalMin=Math.round(h*60);
  if(totalMin<60)return totalMin+" min";
  const hrs=Math.floor(totalMin/60),mins=totalMin%60;
  return hrs+(hrs===1?" hour":" hours")+(mins?` ${mins} min`:"");
}

function checkOven(styleKey,ovenTemp){
  const b=STYLES[styleKey].bake;if(ovenTemp==null||ovenTemp==="")return null;const t=Number(ovenTemp),name=STYLES[styleKey].name.toLowerCase();
  if(t>b.max)return{level:"warn",message:`${tF(t)} is hotter than ${name} wants — it may colour or scorch before the inside is ready. Aim for ${tF(b.min)}–${tF(b.max)}.`};
  if(t>=b.idealMin)return{level:"ok",message:`Your temperature is in the right range for this style.`};
  if(t<b.min-20)return{level:"warn",message:`${tF(t)} is well below the recommended ${tF(b.min)}–${tF(b.max)} range. The bake-time estimate becomes unreliable and the crust may dry before it colours.`};
  if(PAN_STYLES.includes(styleKey)||LEAN_BREAD_STYLES.includes(styleKey))return{level:"adjust",message:`Below the ideal ${tF(b.idealMin)} — allow a longer bake and judge by colour and internal doneness rather than the clock alone.`};
  return{level:"adjust",message:`Below the ${tF(b.idealMin)} this style wants. Use the oven's maximum with a fully preheated stone or steel and bake until the crust colours.`};
}


function runEngineSelfTests(){
  const cases=[
    calculate({styleKey:"neapolitan",methodKey:"easy",quantity:2,size:{diameter:12},ambientC:25,flourProtein:11,ovenTemp:425,timeframe:"sameday"}),
    calculate({styleKey:"roman",methodKey:"trad",preferment:"poolish",quantity:1,size:{length:12,width:8},ambientC:24,flourProtein:12.5,ovenTemp:250,timeframe:"nextday"}),
    calculate({styleKey:"ciabatta",methodKey:"trad",preferment:"poolish",quantity:2,ambientC:24,flourProtein:12.5,ovenTemp:235,timeframe:"nextday"}),
    calculate({styleKey:"softbread",methodKey:"easy",quantity:12,breadFormat:"rolls",ambientC:24,flourProtein:11.5,ovenTemp:190,timeframe:"sameday"}),
    calculate({styleKey:"baguette",methodKey:"trad",preferment:"poolish",quantity:2,ambientC:24,flourProtein:12.5,ovenTemp:240,timeframe:"nextday"})
  ];
  cases.forEach((r,i)=>{
    console.assert(Number.isFinite(r.totals.doughWeight)&&r.totals.doughWeight>0,`Dough test ${i+1}: positive dough weight`);
    console.assert(r.ingredients.flour>0&&r.ingredients.water>=0,`Dough test ${i+1}: flour and water valid`);
    console.assert(Math.abs(r.totalTime-Object.values(r.stages).reduce((a,s)=>a+s.val,0))<0.01,`Dough test ${i+1}: stage total matches`);
    console.assert(r.stageAmounts.water.final>=0&&r.stageAmounts.flour.final>=0,`Dough test ${i+1}: no negative final-stage quantities`);
    const retained=r.totals.grossDough*(1-r.loss.val/100);
    console.assert(Math.abs(retained-r.totals.doughWeight)<2,`Dough test ${i+1}: loss allowance retains target dough`);
  });
  console.assert(cases[3].totals.ballWeight===70,"Soft-roll default portion is 70 g");
  const ny12=calculate({styleKey:"ny",methodKey:"easy",quantity:1,size:{diameter:12},ambientC:25,flourProtein:12,ovenTemp:350,totalHours:8});
  console.assert(ny12.totals.ballWeight>=295&&ny12.totals.ballWeight<=315,"12-inch New York dough is about 300 g");
  const maturePoolish=calculate({styleKey:"baguette",methodKey:"trad",preferment:"poolish",quantity:2,ambientC:25,flourProtein:12.5,ovenTemp:240,totalHours:16});
  console.assert(maturePoolish.mainYeastRec===0,"Mature lean-bread poolish needs no finishing yeast by default");
  const impossible=calculate({styleKey:"neapolitan",methodKey:"trad",preferment:"poolish",quantity:2,ambientC:25,flourProtein:11,ovenTemp:425,totalHours:12,overrides:{hydration:58,poolishPct:100,prefHydration:100}});
  console.assert(impossible.stageAmounts.water.final>=0&&impossible.preferment.adjusted,"Impossible preferment water load is clamped and flagged");

  const cold48=calculate({styleKey:"ny",methodKey:"easy",quantity:2,size:{diameter:16},ambientC:22,fridgeC:4,fermentationMode:"cold",flourProtein:12,ovenTemp:350,timeframe:"2-3day"});
  console.assert(cold48.timeRange.supported&&cold48.timeRange.min<=36&&cold48.timeRange.max>=72,"Cold plan exposes a broad 36–72 h planning window");
  console.assert(Math.abs(cold48.mainYeastRec-0.10)<=0.01,"48 h / 4°C cold plan uses about 0.10% IDY");
  console.assert(cold48.stages.cold&&cold48.stages.cold.val>cold48.stages.bulk.val,"Cold plan separates a substantial refrigerator hold from warm stages");
  const coldPrefPlan=recommendedTotalPlan("baguette","trad","poolish",25,"cold","nextday",4);
  const coldPref=calculate({styleKey:"baguette",methodKey:"trad",preferment:"poolish",quantity:2,ambientC:25,fridgeC:4,fermentationMode:"cold",timeframe:"nextday",totalHours:coldPrefPlan.central,flourProtein:12.5,ovenTemp:240});
  console.assert(coldPrefPlan.central===30&&coldPref.stages.cold.val>=20,"Cold preferment time is added before the completed-dough cold plan");

  const coldRoomMisuse=calculate({styleKey:"ny",methodKey:"easy",quantity:1,size:{diameter:12},ambientC:4,fermentationMode:"room",flourProtein:12,ovenTemp:350,timeframe:"sameday"});
  console.assert(coldRoomMisuse.timeRange.supported===false,"Room model refuses refrigerator-temperature timing");
  const hotRoom=calculate({styleKey:"ny",methodKey:"easy",quantity:1,size:{diameter:12},ambientC:38,fermentationMode:"room",flourProtein:12,ovenTemp:350,timeframe:"sameday",mixMode:"stand"});
  console.assert(hotRoom.timeRange.supported===false,"Room model refuses authoritative timing above 35°C");
  console.assert(hotRoom.water.feasible===false&&hotRoom.water.message.includes("cannot"),"Impossible water-temperature target is reported explicitly");

  const youngPf=prefermentMaturity("poolish",4,25,0.01,"instant");
  const pastPf=prefermentMaturity("poolish",8,25,1.0,"instant");
  console.assert(youngPf.status==="young"&&pastPf.status==="past","Preferment maturity uses time, temperature and yeast dose from one source");
}
runEngineSelfTests();

/* ===== UI CONTROLLER ===== */
const $=id=>document.getElementById(id);
function setTheme(mode){
  const theme = mode === "dark" ? "dark" : "light";
  document.documentElement.dataset.theme = theme;
  try{localStorage.setItem("doughTheme",theme);}catch(e){}
  const btn=$("themeToggle");
  if(btn)btn.textContent = theme === "dark" ? "Light mode" : "Dark mode";
  if(theme !== "dark") setUV(false);
}
function initTheme(){
  // Always land in light mode. Dark is a per-session toggle and is intentionally
  // NOT restored on reload, so every fresh visit opens light.
  setTheme("light");
}
const advIds=["hydration","salt","oil","sugar","milkPowder"];
let current="neapolitan", currentMethod="easy", mode="brief", mixMode="hand", breadFormat="loaf", appMode="easy", fermentationMode="room";
let currentTimeframe=null;  // Guided timeframe and fermentation-location controls.
let userShape="round";
let touched={};
let ballTouched=false;
let yeastTouched={};
let stageTouched={};
let prefTouched={};
let lossTouched=false;
let totalTouched=false;
let vinToggleTouched=false;
let vinTouched=false;

const METHOD_BLURB={
  easy:"Direct dough — everything is mixed into one dough. It is the simplest and most predictable method.",
  trad:"Uses a poolish or biga made ahead, then completed into the final dough. It adds planning and gives more control over flavour and structure."
};
const STYLE_GUIDANCE={
  neapolitan:{best:"Best for very hot ovens, minimal toppings, a soft centre and a puffy cornicione.",topping:"Keep toppings minimal. Excess sauce, cheese or wet topping overloads the thin base."},
  ny:{best:"Best for foldable slices, moderate toppings and a crisp but flexible base.",topping:"Use moderate sauce and cheese so the slice still folds without collapsing."},
  detroit:{best:"Best for pan baking, crisp cheese edges, a fried base and a thicker crumb.",topping:"It carries more topping than thin pizza, but wet toppings can still collapse the crumb."},
  roman:{best:"Best for airy tray pizza cut into pieces, with a crisp base and open crumb.",topping:"Use restrained wet toppings until the base has set; a staged bake can help."},
  focaccia:{best:"Best when the bread is the point: oil-rich crumb, deep dimples and a moist interior.",topping:"Keep it bread-forward. Toppings should support the focaccia rather than bury it."},
  ciabatta:{best:"Best for sandwiches, dipping and an open irregular crumb.",topping:"Handle gently after bulk fermentation; degassing is the main enemy."},
  baguette:{best:"Best for a thin crisp crust, open crumb and long lean loaves.",topping:"Steam early, score decisively and vent late for a dry crust."},
  softbread:{best:"Best for sandwiches, toast or soft dinner rolls from the same enriched dough.",topping:"Proof fully but bake before the structure weakens."}
};
const STYLE_READY_CUES={
  neapolitan:"The ball is relaxed, lightly puffy and gassy around the edge. It opens from the centre without snapping back, while the rim still holds visible gas.",
  ny:"The ball is relaxed and lightly aerated, stretches into an even round without tearing, and still has enough strength to lift and launch.",
  detroit:"The panned dough is puffy and aerated, reaches the corners without force, and slowly returns from a gentle press.",
  roman:"The tray dough is light, bubbly and visibly aerated. It reaches the corners gently and jiggles without flowing like batter.",
  focaccia:"The panned dough is puffy, jiggly and full of visible gas. A dimple remains while the surrounding dough still feels resilient.",
  ciabatta:"The dough is aerated and elastic after bulk; the divided pieces feel light and fragile. Final proof adds modest expansion rather than a full doubling.",
  baguette:"The shaped loaves are roughly 50–75% larger and feel lighter. A gentle press returns slowly without the surface collapsing.",
  softbread:"The loaf or rolls are very puffy and about 75–90% larger. A light press returns slowly; immediate spring means under-proofed, while a fragile dent suggests they are near or past their limit."
};
const COMMON_TROUBLESHOOTING=[
  ["Dough too sticky","First cool it, rest it and use wet hands plus a scraper. Add flour only if it still cannot hold structure after development; extra flour changes the formula."],
  ["Dough tears","If it snaps back, rest it. If it stretches thin and then rips or spreads, the flour may be too weak, the hydration too high or the dough over-fermented."],
  ["Dough is running late","Move it somewhere slightly warmer and judge the dough cues. Do not add raw yeast to an already mixed dough."],
  ["Dough is running early","Cool it, shorten the remaining stage or bake sooner. Next time use less yeast or a colder plan."],
  ["Dough collapsed","It is usually over-fermented, overheated or too weak for the hydration. Handle minimally and bake if salvageable; reduce yeast, time or hydration next time."],
  ["Crust or base is pale","Preheat longer, improve direct heat and avoid overloading with wet toppings. Colour is a better guide than the timer alone."]
];
const STYLE_TROUBLESHOOTING={
  neapolitan:[["Rim stays flat","Do not press the rim, reduce topping load, complete the ball proof and use the highest practical heat."],["Centre tears","Open more gradually, allow more relaxation or lower hydration for the flour."]],
  ny:[["Slice is crisp but rigid","Use a slightly thicker loading, shorten the bake or reduce bottom heat."],["Slice folds but is soggy","Use less wet topping and stronger bottom heat, then rest briefly on a rack."]],
  detroit:[["Base is greasy rather than crisp","Use less pan oil, bake until the underside sets and remove from the pan soon after baking."],["Centre is dense","Proof longer in the pan and avoid forcing tight dough into the corners."]],
  roman:[["Crumb is flat","Preserve gas while moving it into the tray and use a staged bake for wet toppings."],["Base softens","Set the base before adding wet toppings and cool on a rack rather than in the tray."]],
  focaccia:[["Crumb is tight","Allow a fuller pan proof and dimple without crushing every bubble."],["Bottom is oily and pale","Use less pan oil or stronger bottom heat, and remove from the pan after a short rest."]],
  ciabatta:[["Crumb is closed","Avoid reshaping after division, build strength during bulk and handle the final pieces as little as possible."],["Loaf spreads flat","Use stronger flour, lower hydration slightly or shorten fermentation."]],
  baguette:[["Scores do not open","Proof a little less, score at a shallow angle and use steam immediately after loading."],["Crust softens","Vent the oven late and cool fully in open air before storing."]],
  softbread:[["Loaf caves after baking","It was commonly over-proofed or under-baked. Proof slightly less and verify the centre temperature."],["Rolls are firm or dry","Do not add excess bench flour; bake only until done and brush with butter after baking for a softer crust."]]
};
const STYLE_UV_SECRETS={
  neapolitan:"Cornicione checkpoint: open from the centre and herd the gas outward. If you crush the rim, the oven cannot resurrect it.",
  ny:"Fold-test ghost note: the slice should bend without cracking — and without dumping its toppings down your shirt.",
  detroit:"Corner-piece law: whoever made the dough gets first claim on the crispy cheese corner.",
  roman:"Tray-pizza clue: preserve the gas while easing it to the corners; force is the enemy of an open crumb.",
  focaccia:"Dimple like you mean it: press all the way down so oil and salt have somewhere to sit.",
  ciabatta:"Divide, do not reshape. Every unnecessary squeeze closes another hole.",
  baguette:"The score is a controlled rupture. Too shallow and the loaf chooses its own weak point.",
  softbread:"A soft loaf needs a complete final proof more than it needs a dramatic open crumb."
};
const METHOD_UV_SECRETS={
  easy:"Direct dough secret: the mixer starts the dough, but time finishes it. Do not rush the final rest.",
  poolish:"Poolish clue: sweet, creamy, bubbly and alive is good; sharp, boozy and collapsed means it has gone too far.",
  biga:"Biga clue: break it up properly when adding water. Dry clumps hide like little flour rocks inside the final dough."
};
const RECIPE_UV_SECRETS={
  neapolitan:{easy:"Neapolitan direct: the long ball ferment loads the airy rim.",poolish:"Let the poolish bring aroma, then give the balls time to rebuild gas.",biga:"The flour is mature already; the final proof wakes the dough back up."},
  ny:{easy:"Keep the toppings moderate; foldability is a structural test.",poolish:"Poolish softens the chew and adds aroma.",biga:"Biga adds strength and chew; do not roll it dead."},
  detroit:{easy:"The pan does half the cooking. Oil plus metal makes the fried base.",poolish:"Airy is good, but wet toppings steal structure.",biga:"Strong dough, crisp edges and serious corner politics."},
  roman:{easy:"The tray proof loads the crumb; pressing hard unloads it.",poolish:"Extensibility makes tray spreading easier.",biga:"Strength helps a wet dough hold its open structure."},
  focaccia:{easy:"Dimples hold oil, salt and little pools of flavour.",poolish:"Patience supports the softer crumb.",biga:"Stronger and chewier, but still bread first."},
  ciabatta:{easy:"Divide, do not reshape.",poolish:"Preserve the bubbles the preferment helped create.",biga:"Strength without gentle handling still gives a closed crumb."},
  baguette:{easy:"Shaping and steam expose every shortcut.",poolish:"Aroma and extensibility suit the long shape.",biga:"Strong dough needs a complete bench rest before shaping."},
  softbread:{easy:"Full proof matters more than a long ferment.",poolish:"Flavour rises, but tenderness still comes from enrichment.",biga:"Use strength to support the loaf, not to make it chewy."}
};

const stylesEl=$("styles");
const STYLE_IMAGES={
  neapolitan:"data:image/jpeg;base64,",ny:"data:image/jpeg;base64,",detroit:"data:image/jpeg;base64,",roman:"data:image/jpeg;base64,",
  focaccia:"data:image/jpeg;base64,",ciabatta:"data:image/jpeg;base64,",baguette:"data:image/jpeg;base64,",softbread:"data:image/jpeg;base64,"
};
const STYLE_THUMB_IMAGES={baguette:"data:image/jpeg;base64,"};
function expandStyle(k){
  const wrap=$("styleExpand"),img=$("styleExpandImg");
  if(!wrap||!img)return;
  img.src=STYLE_IMAGES[k];img.alt=STYLES[k].name;wrap.classList.add("open");
}
function collapseStyle(){const wrap=$("styleExpand");if(wrap)wrap.classList.remove("open");}
if(stylesEl){
  STYLE_ORDER.forEach(k=>{
    const cell=document.createElement("div");cell.className="style-cell";
    const button=document.createElement("button");button.type="button";button.className="style-btn"+(k===current?" active":"");button.textContent=STYLES[k].name;
    const trigger=e=>{e.stopPropagation();selectStyle(k);expandStyle(k);};
    button.addEventListener("click",trigger);
    const image=document.createElement("img");image.className="style-thumb";image.src=STYLE_THUMB_IMAGES[k]||STYLE_IMAGES[k];image.alt=STYLES[k].name;image.loading="eager";image.decoding="async";image.addEventListener("click",trigger);
    cell.append(button,image);stylesEl.appendChild(cell);
  });
}
document.addEventListener("click",collapseStyle);
if($("styleExpand"))$("styleExpand").addEventListener("click",e=>e.stopPropagation());

function fmtPct(v){return v+"%";}
function ambientC(){const el=$("ambient");return el?tempToBase(num(el.value,tempFromBase(AMBIENT_BASELINE_C))):AMBIENT_BASELINE_C;}
function fridgeC(){const el=$("fridgeTemp");return el?tempToBase(num(el.value,tempFromBase(4))):4;}
function flourProteinVal(){return Math.max(7,num($("flourProtein").value,STYLE_DEFAULT_PROTEIN[current]||12));}
function anyTimeTouched(){return totalTouched||stageTouched.bulk||stageTouched.ball||stageTouched.cold||stageTouched.preferment;}
function sumStages(){
  let sum=num($("sBulk").value,0)+num($("sBall").value,0);
  if(fermentationMode==="cold"&&$("sCold"))sum+=num($("sCold").value,0);
  if(currentMethod==="trad"&&$("sPreferment"))sum+=num($("sPreferment").value,0);
  return sum;
}
function lockAllStages(){
  stageTouched.bulk=true;stageTouched.ball=true;
  if(fermentationMode==="cold")stageTouched.cold=true;
  if(currentMethod==="trad")stageTouched.preferment=true;
}
function syncTotalFromStages(){if($("totalHours"))$("totalHours").value=r2(sumStages());updateTotalRec();}
function syncVinegarUI(){
  const isTrad=currentMethod!=="easy",field=$("vinegarField");
  if(field)field.style.display=isTrad?"none":"";
  const on=$("vinegarOn")&&$("vinegarOn").checked&&!isTrad,wrap=$("vinegarPctWrap");
  if(wrap)wrap.style.display=on?"":"none";
}

const TIMEFRAME_NOTES={
  "":"Choose a timeframe. Easy mode selects a simple plan; Expert mode leaves method and stages under your control.",
  asap:"Fast room-temperature dough for today. More yeast and less development; use the readiness cues rather than forcing the clock.",
  sameday:"Room-temperature dough for later today. This is the simplest first recipe.",
  nextday:"Easy mode uses a refrigerated direct dough for tomorrow, with a warm start and a warm final proof.",
  "2-3day":"Easy mode uses a longer refrigerated dough. The cold hold is shown as a broad window because refrigerators and dough masses vary."
};
function syncFermentationUI(){
  document.querySelectorAll('[data-ferment-mode]').forEach(b=>b.classList.toggle('on',b.dataset.fermentMode===fermentationMode));
  if($("fridgeTempField"))$("fridgeTempField").style.display=fermentationMode==="cold"?"":"none";
  if($("sColdField"))$("sColdField").style.display=fermentationMode==="cold"?"":"none";
  if($("bulkStageLabel"))$("bulkStageLabel").textContent=fermentationMode==="cold"?"Warm start before refrigeration":"Bulk ferment";
  if($("fermentationModeNote"))$("fermentationModeNote").textContent=fermentationMode==="cold"
    ? "This plan separates the warm start, refrigerated hold and warm final proof. The cold stage is an estimated window, not an exact deadline."
    : "Room-temperature timing uses the kitchen temperature continuously. Recommendations are shown as windows and must be checked against the dough.";
}
function setFermentationMode(mode,rerender=true){
  fermentationMode=mode==="cold"?"cold":"room";
  stageTouched={};yeastTouched={};totalTouched=false;
  syncFermentationUI();
  if($("totalHours"))$("totalHours").value=defaultTotalFor();
  updateTotalRec();
  if(rerender){refreshStageDefaults();render();}
}
function updateTimeframeUI(){
  if($("timeframe"))$("timeframe").value=currentTimeframe||"";
  if($("timeframeNote"))$("timeframeNote").textContent=TIMEFRAME_NOTES[currentTimeframe||""];
}
function applyTimeframe(tf){
  if(!tf){
    if(appMode==="easy")tf="sameday";
    else{currentTimeframe=null;updateTimeframeUI();render();return;}
  }
  currentTimeframe=tf;
  if(appMode==="easy"){
    fermentationMode=(tf==="nextday"||tf==="2-3day")?"cold":"room";
    currentMethod="easy";
    if($("preferment"))$("preferment").value="poolish";
  }
  stageTouched={};prefTouched={};yeastTouched={};totalTouched=false;
  syncMethodUI();syncFermentationUI();
  $("totalHours").value=defaultTotalFor();
  updateTotalRec();refreshStageDefaults();updateTimeframeUI();render();
}
function clearTimeframe(){if(currentTimeframe!==null){currentTimeframe=null;updateTimeframeUI();}}
function currentTimePlan(){
  return recommendedTotalPlan(current,currentMethod,$("preferment").value,ambientC(),fermentationMode,currentTimeframe,fridgeC());
}
function defaultTotalFor(){return currentTimePlan().central;}
function updateTotalRec(){
  const p=currentTimePlan();
  $("totalRec").textContent=fmtH(p.min)+"–"+fmtH(p.max);
}
function getSize(){const s=STYLES[current];if(s.sizing==="weight")return{};if(userShape==="round")return{diameter:lenToBase($("diameter").value)};const o={length:lenToBase($("panL").value),width:lenToBase($("panW").value)};if(s.hasDepth&&$("panDepth"))o.depth=lenToBase($("panDepth").value);return o;}

function recalcRecommendations(){
  // compute a fresh calc with NO stage/pref overrides to get recommended stage values
  const s=STYLES[current];
  const baseCalc=calculate({styleKey:current,methodKey:currentMethod,quantity:num($("qty").value,2),
    size:getSize(),overrides:(touched.hydration?{hydration:$("hydration").value}:{}),yeastType:$("yeastType").value,preferment:$("preferment").value,
    poolishStyle:$("poolishStyle").value,totalHours:num($("totalHours").value,defaultTotalFor()),
    ovenTemp:tempToBase($("oven").value),shape:userShape,mixMode,ambientC:ambientC(),fridgeC:fridgeC(),fermentationMode,flourProtein:flourProteinVal(),timeframe:currentTimeframe,breadFormat});
  return baseCalc;
}

function uvMarker(text){
  if(!text)return "";
  // wrap each word in its own secret span so the torch reveals text word-by-word as it sweeps
  const words=text.split(/\s+/).map(w=>`${esc(w)}`).join(" ");
  return ` ${words}`;
}
function renderDescription(styleKey){
  const el=$("desc");
  el.innerHTML=esc(STYLES[styleKey].description)+uvMarker(STYLE_UV_SECRETS[styleKey]);
}
function renderMethodBlurb(){
  const methodSecretKey=currentMethod==="trad" ? $("preferment").value : "easy";
  $("methodBlurb").innerHTML=esc(METHOD_BLURB[currentMethod])+uvMarker(METHOD_UV_SECRETS[methodSecretKey]);
}
function getRecipeUVSecret(r){
  const methodSecretKey=r.isTrad ? r.preferment.type : "easy";
  return (RECIPE_UV_SECRETS[r.styleKey]&&RECIPE_UV_SECRETS[r.styleKey][methodSecretKey])||"";
}
function renderRecipeUVSecret(r){
  const el=$("recipeSecret");
  if(el)el.innerHTML="";
}

function applyShapeUI(setDefaults){
  const s=STYLES[current], weightSized=s.sizing==="weight";
  if($("shapeField"))$("shapeField").style.display=weightSized?"none":"";
  $("roundSize").style.display=!weightSized&&userShape==="round"?"":"none";
  $("rectSize").style.display=!weightSized&&userShape==="rectangle"?"":"none";
  $("depthField").style.display=!weightSized&&s.hasDepth?"":"none";
  if($("breadFormatField"))$("breadFormatField").style.display=current==="softbread"?"":"none";
  document.querySelectorAll('[data-shape]').forEach(b=>b.classList.toggle('active',b.dataset.shape===userShape));
  if(setDefaults){
    if(userShape==="round"){const d=roundDefIn(s);$("diameter").value=fmtLenNum(d);$("diameterRec").textContent=fmtLenNum(d)+" "+lenLabel();}
    else{const dl=rectDefIn(s);$("panL").value=fmtLenNum(dl.l);$("panW").value=fmtLenNum(dl.w);}
  } else if(userShape==="round"){const d=roundDefIn(s);$("diameterRec").textContent=fmtLenNum(d)+" "+lenLabel();}
}
function setShape(shp){ if(userShape===shp) return; userShape=shp; ballTouched=false; applyShapeUI(true); refreshStageDefaults(); render(); }
function setBreadFormat(fmt){
  if(current!=="softbread"||breadFormat===fmt)return;
  breadFormat=fmt; userShape=fmt==="rolls"?"round":"rectangle"; ballTouched=false;
  $("qty").value=fmt==="rolls"?12:1;
  if($("qtyLabel"))$("qtyLabel").textContent="How many "+styleUnitName(current,true);
  if($("qtyRec"))$("qtyRec").textContent=fmt==="rolls"?12:1;
  document.querySelectorAll('[data-bread-format]').forEach(b=>b.classList.toggle('active',b.dataset.breadFormat===fmt));
  applyShapeUI(false); refreshStageDefaults(); render();
}
function styleUnitName(styleKey,plural=true){
  if(styleKey==="roman")return plural?"trays":"tray";
  if(styleKey==="baguette")return plural?"baguettes":"baguette";
  if(styleKey==="ciabatta")return plural?"loaves":"loaf";
  if(styleKey==="softbread")return breadFormat==="rolls"?(plural?"rolls":"roll"):(plural?"loaves":"loaf");
  if(PAN_STYLES.includes(styleKey)||LEAN_BREAD_STYLES.includes(styleKey))return plural?"pans":"pan";
  return plural?"pizzas":"pizza";
}
function setAppMode(next,doRender=true){
  appMode=next==="expert"?"expert":"easy";
  document.body.classList.toggle("easy-mode",appMode==="easy");
  if($("easyModeBtn"))$("easyModeBtn").classList.toggle("on",appMode==="easy");
  if($("expertModeBtn"))$("expertModeBtn").classList.toggle("on",appMode==="expert");
  if($("modeNote"))$("modeNote").textContent=appMode==="easy"
    ? "Easy mode chooses the dough method, hydration, yeast and timing windows. You choose what you are making, the flour, when you need it, room or refrigerator fermentation, your temperatures and your oven."
    : "Expert mode exposes baker's percentages, preferment construction, fermentation stages, yeast doses and dough-loss controls.";
  try{localStorage.setItem("doughAppMode",appMode);}catch(e){}
  const custom=$("customTimeOption"),longOpt=$("longTimeOption");
  if(custom)custom.hidden=appMode==="easy";
  if(longOpt)longOpt.hidden=false;
  document.querySelectorAll('[data-easy-title]').forEach(el=>{el.textContent=appMode==="easy"?el.dataset.easyTitle:el.dataset.expertTitle;});
  const numbered=[...document.querySelectorAll('.section-box .sec-num')];
  numbered.forEach(n=>{if(!n.dataset.original)n.dataset.original=n.textContent;});
  if(appMode==="easy"){
    let i=1;numbered.forEach(n=>{const box=n.closest('.section-box');if(!box.classList.contains('expert-only'))n.textContent=String(i++);});
    if(!currentTimeframe)currentTimeframe="sameday";
    fermentationMode=(currentTimeframe==="nextday"||currentTimeframe==="2-3day")?"cold":"room";
    currentMethod="easy";if($("preferment"))$("preferment").value="poolish";
    mode="brief";
    if(mixMode==="spiral")mixMode="stand";
    if(typeof syncMixUI==="function")syncMixUI();
    if($("briefBtn"))$("briefBtn").classList.add("on");
    if($("expandBtn"))$("expandBtn").classList.remove("on");
  }else numbered.forEach(n=>n.textContent=n.dataset.original);
  syncMethodUI();syncFermentationUI();updateTimeframeUI();
  if(doRender&&$("totalHours")){
    stageTouched={};prefTouched={};yeastTouched={};totalTouched=false;
    $("totalHours").value=defaultTotalFor();refreshStageDefaults();render();
  }
}
function selectStyle(k){
  current=k;touched={};stageTouched={};prefTouched={};yeastTouched={};ballTouched=false;lossTouched=false;totalTouched=false;vinToggleTouched=false;vinTouched=false;
  [...stylesEl.querySelectorAll(".style-btn")].forEach((b,i)=>b.classList.toggle("active",STYLE_ORDER[i]===k));
  const s=STYLES[k];
  breadFormat="loaf";
  const defProtein=STYLE_DEFAULT_PROTEIN[k]||12;
  const keepExpertFlour=appMode==="expert"&&$("flourProtein")&&Number.isFinite(Number($("flourProtein").value));
  if(!keepExpertFlour&&$("flourProtein"))$("flourProtein").value=defProtein;
  if(!keepExpertFlour&&$("flourType")){
    const choices=[...$("flourType").options].map(o=>Number(o.value)).filter(Number.isFinite);
    const closest=choices.sort((a,b)=>Math.abs(a-defProtein)-Math.abs(b-defProtein))[0];
    $("flourType").value=String(closest);
  }
  if(appMode==="easy"){
    if(!currentTimeframe)currentTimeframe="sameday";
    fermentationMode=(currentTimeframe==="nextday"||currentTimeframe==="2-3day")?"cold":"room";
    currentMethod="easy";
    if($("preferment"))$("preferment").value="poolish";
    syncFermentationUI();
  }
  $("qty").value=s.defaultQty||2;
  if($("qtyRec"))$("qtyRec").textContent=s.defaultQty||2;
  if($("qtyLabel"))$("qtyLabel").textContent="How many "+styleUnitName(k,true);
  userShape=s.shape;
  document.querySelectorAll('[data-bread-format]').forEach(b=>b.classList.toggle('active',b.dataset.breadFormat==="loaf"));
  applyShapeUI(true);
  if(s.hasDepth){$("panDepth").value=fmtLenNum(s.defaultDepth);$("panDepthRec").textContent=fmtLenNum(s.depthMin)+"–"+fmtLenNum(s.depthMax)+" "+lenLabel();}
  $("totalHours").value=defaultTotalFor();updateTotalRec();
  $("oven").value=Math.round(tempFromBase(s.bake.idealMin));$("ovenRec").textContent=tF(s.bake.idealMin)+"–"+tF(s.bake.max);
  if($("bakeBase"))$("bakeBase").value=PAN_STYLES.includes(k)?"tray":(LEAN_BREAD_STYLES.includes(k)?"stone":"steel");
  syncBakeUI();
  $("hydration").value=recHydrationFor(s.hydration,flourProteinVal());$("hydrationRec").textContent=fmtPct(recHydrationFor(s.hydration,flourProteinVal()));
  $("salt").value=s.salt;$("saltRec").textContent=fmtPct(s.salt);
  $("oil").value=s.oil;$("oilRec").textContent=fmtPct(s.oil);
  $("sugar").value=s.sugar;$("sugarRec").textContent=fmtPct(s.sugar);$("milkPowder").value=s.milkPowder||0;$("milkPowderRec").textContent=fmtPct(s.milkPowder||0);
  renderDescription(k);
  refreshStageDefaults();
  render();
}

function resetFlourMethod(){
  // Section 2 — Flour and Method Selection — back to load defaults: blank flour protein (treated as 12%),
  // no chosen flour type, vinegar off, instant yeast, all-in-one (Simple) method, stand mixer.
  const dp=STYLE_DEFAULT_PROTEIN[current]||12; $("flourProtein").value=dp;
  const opts=[...$("flourType").options].map(o=>Number(o.value)).filter(Number.isFinite);
  $("flourType").value=String(opts.sort((a,b)=>Math.abs(a-dp)-Math.abs(b-dp))[0]);
  if($("yeastType")) $("yeastType").value="instant";
  if($("vinegarOn")) $("vinegarOn").checked=false;
  vinTouched=false; vinToggleTouched=false;
  if(typeof syncVinegarUI==="function") syncVinegarUI();
  mixMode=appMode==="easy"?"hand":"stand"; if(typeof syncMixUI==="function") syncMixUI();
  if(appMode==="easy"){
    fermentationMode=((currentTimeframe||"sameday")==="nextday"||(currentTimeframe||"sameday")==="2-3day")?"cold":"room";
    currentMethod="easy";
    if($("preferment"))$("preferment").value="poolish";
    syncFermentationUI();
  }else currentMethod="easy";
  stageTouched={}; prefTouched={}; yeastTouched={}; totalTouched=false;
  $("totalHours").value=defaultTotalFor(); updateTotalRec();
  syncMethodUI(); refreshStageDefaults(); render();
}
function resetPreferment(){
  // Section 3 — Preferment Recipe Control — back to defaults: poolish type, chewier finish, and the
  // recommended amount / hydration / time / yeast. Scoped to the preferment only — the Simple vs
  // Preferment method choice lives in Section 2, and the bulk/ball timers are left as they are.
  if($("preferment")) $("preferment").value="poolish";
  if($("poolishStyle")) $("poolishStyle").value="stiff";
  prefTouched={};
  stageTouched.preferment=false;
  yeastTouched.preferment=false;
  syncMethodUI(); refreshStageDefaults(); render();
}
function resetTime(){
  // restore the Time & Timers section to defaults: ambient back to typical room, timeframe to Custom,
  // stage timers cleared to recommended. (Ambient is reset too — it's a section default; if Mark wants
  // the identified-environment ambient to persist through a reset, this is the one line to drop.)
  $("ambient").value=Math.round(tempFromBase(AMBIENT_BASELINE_C));
  $("ambientRec").textContent=tF(AMBIENT_BASELINE_C);
  currentTimeframe=appMode==="easy"?"sameday":null;
  fermentationMode="room";
  if($("fridgeTemp"))$("fridgeTemp").value=Math.round(tempFromBase(4));
  if(appMode==="easy"){currentMethod="easy";if($("preferment"))$("preferment").value="poolish";}
  syncFermentationUI();
  stageTouched={};prefTouched={};yeastTouched={};totalTouched=false;
  $("totalHours").value=defaultTotalFor();
  updateTotalRec();syncMethodUI();refreshStageDefaults();updateTimeframeUI();render();
}
function resetIngredients(){
  const s=STYLES[current];
  touched={};yeastTouched={};vinTouched=false;vinToggleTouched=false;lossTouched=false;
  const hr=recHydrationFor(s.hydration,flourProteinVal());
  $("hydration").value=hr;$("hydrationRec").textContent=fmtPct(hr);
  $("salt").value=s.salt;$("saltRec").textContent=fmtPct(s.salt);
  $("oil").value=s.oil;$("oilRec").textContent=fmtPct(s.oil);
  $("sugar").value=s.sugar;$("sugarRec").textContent=fmtPct(s.sugar);$("milkPowder").value=s.milkPowder||0;$("milkPowderRec").textContent=fmtPct(s.milkPowder||0);
  if(typeof syncVinegarUI==="function") syncVinegarUI();
  refreshStageDefaults();render();
}
function resetBake(){
  const s=STYLES[current];
  $("oven").value=Math.round(tempFromBase(s.bake.idealMin));$("ovenRec").textContent=tF(s.bake.idealMin)+"–"+tF(s.bake.max);
  if($("bakeBase"))$("bakeBase").value=PAN_STYLES.includes(current)?"tray":(LEAN_BREAD_STYLES.includes(current)?"stone":"steel");
  if($("ovenType"))$("ovenType").value="home";
  syncBakeUI();render();
}

function refreshStageDefaults(){
  // populate stage time inputs + preferment fields with recommended (only if not touched)
  const rc=recalcRecommendations();
  // hydration: recommended value follows flour protein
  const hydRec=recHydrationFor(STYLES[current].hydration, flourProteinVal());
  if($("hydrationRec"))$("hydrationRec").textContent=fmtPct(hydRec);
  if(!touched.hydration&&$("hydration"))$("hydration").value=hydRec;
  // dough loss allowance: rec from live hydration + mix mode, measured against the protein-adjusted hydration
  const lossRec=recLossFor($("hydration").value, hydRec, mixMode);
  if($("lossAllowRec"))$("lossAllowRec").textContent=lossRec+"%";
  if(!lossTouched&&$("lossAllow"))$("lossAllow").value=lossRec;
  // vinegar: rec from protein; sync visibility (method + toggle); fill value if untouched
  syncVinegarUI();
  const vinRec=recVinegarFor(flourProteinVal());
  if($("vinegarRec"))$("vinegarRec").textContent=vinRec+"%";
  if(!vinTouched&&$("vinegar"))$("vinegar").value=vinRec;
  if(!stageTouched.bulk){$("sBulk").value=rc.stages.bulk.val;}
  $("sBulkRec").textContent=fmtHRange(rc.stages.bulk.range);
  if(rc.stages.cold&&$("sCold")){
    if(!stageTouched.cold)$("sCold").value=rc.stages.cold.val;
    if($("sColdRec"))$("sColdRec").textContent=fmtHRange(rc.stages.cold.range);
  }
  if(!stageTouched.ball){$("sBall").value=rc.stages.ball.val;}
  $("sBallRec").textContent=fmtHRange(rc.stages.ball.range);
  if(!yeastTouched.main){$("mainYeast").value=rc.mainYeastRec;}
  $("mainYeastRec").textContent=rc.mainYeastRange[0]+"–"+rc.mainYeastRange[1]+"%";
  if(currentMethod==="trad"){
    if(!stageTouched.preferment){$("sPreferment").value=rc.stages.preferment.val;}
    $("sPrefermentRec").textContent=fmtHRange(rc.stages.preferment.range);
    const pf=PREFERMENTS[$("preferment").value];
    if(!prefTouched.hydration){$("prefHydration").value=pf.hydration;}
    $("prefHydrationRec").textContent=pf.hydration+"%";
    if($("poolishPctField")){
      const prefVal=$("preferment").value;
      $("poolishPctField").style.display=""; // shown for both poolish and biga now
      if($("poolishPctLabel"))$("poolishPctLabel").textContent=(prefVal==="biga"?"Biga":"Poolish")+" amount (% of total flour)";
      if(!prefTouched.poolishPct){$("poolishPct").value=pf.flourPct;}
      $("poolishPctRec").textContent=pf.flourPct+"%";
    }
    if(rc.preferment){
      if(!yeastTouched.preferment){$("prefYeast").value=rc.preferment.yeastRec;}
      $("prefYeastRec").textContent=rc.preferment.yeastRec+"%";
    }
  }
}

function syncMethodUI(){
  if($("mainYeastLabel"))$("mainYeastLabel").textContent=(currentMethod==="trad"?"Finishing yeast (optional)":"Total yeast amount");
  if($("sugarLabel"))$("sugarLabel").textContent=(currentMethod==="trad"?"Secondary sugar / honey":"Sugar / honey");
  if($("mainYeastNote"))$("mainYeastNote").textContent=(currentMethod==="trad"
    ? "Usually zero when the preferment is mature and active. Add a small finishing dose only when you deliberately want a faster final rise."
    : "All the yeast in the dough.");
  if($("sugarNote"))$("sugarNote").textContent=(currentMethod==="trad"
    ? "Sugar added in the final mix. Honey works in its place, 1:1 by weight. Optional — it feeds browning and a slightly faster rise."
    : "Optional — sugar, or honey in its place (1:1 by weight). Feeds browning and a slightly faster rise.");
  $("mEasy").classList.toggle("active",currentMethod==="easy");
  $("mTrad").classList.toggle("active",currentMethod==="trad");
  renderMethodBlurb();
  $("prefGroup").style.display=currentMethod==="trad"?"":"none";
  {const mf=$("sPrefermentMirrorField");if(mf)mf.style.display=currentMethod==="trad"?"":"none";}
  {const s4=$("section4Preferment");if(s4)s4.style.display="";const npn=$("noPrefNote");if(npn)npn.style.display=currentMethod==="trad"?"none":"";}
  // finish (chewier/softer) only matters when there's flour left to add last — hide it at 100%
  const prefVal=$("preferment").value, pctNow=num($("poolishPct").value, PREFERMENTS[prefVal].flourPct);
  $("poolishStyleField").style.display=(currentMethod==="trad" && pctNow<100)?"":"none";
  if($("poolishStyleLabel"))$("poolishStyleLabel").textContent=(prefVal==="biga"?"Biga":"Poolish")+" finish";
  if($("poolishPctField"))$("poolishPctField").style.display=currentMethod==="trad"?"":"none";
  if($("prefTypeNote")){
    $("prefTypeNote").textContent = $("preferment").value==="biga"
      ? "Biga is a stiff, low-hydration preferment, traditionally most or all of the flour — but you can set how much. Any flour not in the biga goes into the final mix."
      : "Poolish uses part of the total flour, then the dough is completed with the remaining flour. This keeps poolish and biga cleanly distinct.";
  }
}

function buildOpts(){
  // NOTE: no protectInputs() here — clamping during typing makes single digits
  // impossible to enter (esp. on mobile). Values are tidied on blur via the
  // change handler instead, so typing stays free.
  const overrides={};advIds.forEach(id=>{if(touched[id])overrides[id]=$(id).value;});
  if(prefTouched.hydration)overrides.prefHydration=$("prefHydration").value;
  if(prefTouched.poolishPct)overrides.poolishPct=$("poolishPct").value;
  if(prefTouched.yeast)overrides.prefYeast=$("prefYeast").value;
  const stageOverrides={};
  if(stageTouched.bulk)stageOverrides.bulk=$("sBulk").value;
  if(stageTouched.ball)stageOverrides.ball=$("sBall").value;
  if(stageTouched.cold&&$("sCold"))stageOverrides.cold=$("sCold").value;
  if(stageTouched.preferment)stageOverrides.preferment=$("sPreferment").value;
  const yeastOverrides={};
  if(yeastTouched.main)yeastOverrides.main=$("mainYeast").value;
  if(yeastTouched.preferment)yeastOverrides.preferment=$("prefYeast").value;
  const bwBase = ballTouched ? wtToBase($("ballWeight").value) : null;
  return {styleKey:current,methodKey:currentMethod,quantity:num($("qty").value,2),size:getSize(),
    overrides,yeastType:$("yeastType").value,preferment:$("preferment").value,
    poolishStyle:$("poolishStyle").value,totalHours:num($("totalHours").value,defaultTotalFor()),
    stageOverrides,yeastOverrides,ovenTemp:tempToBase($("oven").value),mixMode,shape:userShape,
    bakeBase:($("bakeBase")?$("bakeBase").value:"steel"),ovenType:($("ovenType")?$("ovenType").value:"home"),
    ambientC:ambientC(),fridgeC:fridgeC(),fermentationMode,
    flourProtein:flourProteinVal(),
    vinegarOn:$("vinegarOn").checked,
    vinegar: vinTouched ? $("vinegar").value : null,
    lossAllow: lossTouched ? $("lossAllow").value : null,
    ballWeight: (Number.isFinite(bwBase)&&bwBase>0) ? bwBase : null, timeframe:currentTimeframe, breadFormat};
}


let lastRecipeText="";
function clamp(v,min,max,fallback,integer=false){
  let n=Number(v);
  if(!Number.isFinite(n)) n=fallback;
  if(Number.isFinite(min)) n=Math.max(min,n);
  if(Number.isFinite(max)) n=Math.min(max,n);
  return integer?Math.round(n):n;
}
function setClean(id,min,max,fallback,integer=false){
  const el=$(id); if(!el) return fallback;
  const n=clamp(el.value,min,max,fallback,integer);
  el.value=integer?String(n):String(r2(n));
  return n;
}

function setCleanLen(id,minIn,maxIn,defIn){const el=$(id); if(!el) return; let base=lenToBase(el.value); if(!Number.isFinite(base)) base=defIn; base=Math.max(minIn,Math.min(maxIn,base)); el.value=String(fmtLenNum(base));}
function setCleanTemp(id,minC,maxC,defC){const el=$(id); if(!el) return; let c=tempToBase(el.value); if(!Number.isFinite(c)) c=defC; c=Math.max(minC,Math.min(maxC,c)); el.value=String(Math.round(tempFromBase(c)));}
function protectInputs(){
  const s=STYLES[current];
  setClean("qty",1,999,2,true);
  if(userShape==="round") setCleanLen("diameter",6,60,roundDefIn(s));
  else { const dl=rectDefIn(s); setCleanLen("panL",4,60,dl.l); setCleanLen("panW",4,60,dl.w); }
  if(s.hasDepth && $("panDepth")) setCleanLen("panDepth",0.5,5,s.defaultDepth);
  setClean("totalHours",1,120,defaultTotalFor(),false);
  setCleanTemp("oven",150,550,s.bake.idealMin);
  setClean("hydration",40,100,recHydrationFor(s.hydration,flourProteinVal()),false);
  setClean("salt",0,6,s.salt,false);
  setClean("oil",0,15,s.oil,false);
  setClean("sugar",0,8,s.sugar,false);
  setClean("sBulk",0,120,0,false);
  if($("sCold"))setClean("sCold",0.25,168,24,false);
  setClean("sBall",0,120,2,false);
  if($("fridgeTemp"))setCleanTemp("fridgeTemp",1,10,4);
  setClean("mainYeast",0,5,0.1,false);
  if(currentMethod==="trad"){
    setClean("sPreferment",1,120,PREFERMENTS[$("preferment").value].minHours,false);
    setClean("prefHydration",40,120,PREFERMENTS[$("preferment").value].hydration,false);
    setClean("prefYeast",0,3,0.1,false);
    setClean("poolishPct",10,100,PREFERMENTS[$("preferment").value].flourPct,false);
  }
}
function recipeText(r,steps){
  const yt=r.yeastTypeName.toLowerCase();
  const lines=[];
  lines.push(`${r.styleName} dough — ${r.methodName}`);
  lines.push(`${recipeFormatText(r)} · total dough ${gW(r.totals.doughWeight)} · fermentation ${fmtHShort(r.totalTime)}`);
  lines.push("");
  if(lastDevs&&lastDevs.length){
    lines.push("OUTSIDE OUR RECOMMENDATIONS");
    lastDevs.forEach(d=>lines.push(`- ${d.label}: you set ${d.you}, recommended ${d.rec}`));
    lines.push("");
  }
  lines.push("INGREDIENTS");
  if(r.isTrad){
    const pf=r.preferment;
    lines.push(`Step 1 — ${pf.name} (${fmtHRange(pf.timeRange)} room temperature · ${pf.hydration}% hydration)`);
    lines.push(`Flour: ${gW(pf.flour)}`);
    lines.push(`Water: ${gW(pf.water)}`);
    lines.push(`Yeast (${yt}): ${gWy(pf.yeast)}`);
    lines.push("");
    lines.push(`Step 2 — Final dough, add to the ${pf.name.toLowerCase()}`);
    if(r.stageAmounts.flour.final>0) lines.push(`Flour: ${gW(r.stageAmounts.flour.final)}`);
    lines.push(`Water: ${gW(r.stageAmounts.water.final)}`);
    lines.push(`Salt: ${gW(r.ingredients.salt)}`);
    if(r.stageAmounts.finalYeast>0.04) lines.push(`Finishing yeast (${yt}): ${gWy(r.stageAmounts.finalYeast)}`);
    if(r.ingredients.oil!=null) lines.push(`Oil: ${gW(r.ingredients.oil)}`);
    if(r.ingredients.sugar!=null) lines.push(`Sugar: ${gW(r.ingredients.sugar)}`);
    if(r.ingredients.milkPowder!=null) lines.push(`Milk powder: ${gW(r.ingredients.milkPowder)}`);
  }else{
    lines.push(`Flour: ${gW(r.ingredients.flour)}`);
    lines.push(`Water: ${gW(r.ingredients.water)}`);
    if(r.ingredients.vinegar!=null) lines.push(`Vinegar: ${gW(r.ingredients.vinegar)}`);
    lines.push(`Salt: ${gW(r.ingredients.salt)}`);
    lines.push(`Yeast (${yt}): ${gWy(r.ingredients.yeast)}`);
    if(r.ingredients.oil!=null) lines.push(`Oil: ${gW(r.ingredients.oil)}`);
    if(r.ingredients.sugar!=null) lines.push(`Sugar: ${gW(r.ingredients.sugar)}`);
    if(r.ingredients.milkPowder!=null) lines.push(`Milk powder: ${gW(r.ingredients.milkPowder)}`);
  }
  if(r.totals.lossGrams>0){
    lines.push("");
    lines.push("DOUGH TOTALS");
    lines.push(`Total mixed (gross): ${gW(r.totals.grossDough)}`);
    lines.push(`Less ~${r.loss.val}% lost to bowl & hands: -${gW(r.totals.lossGrams)}`);
    lines.push(`Working dough: ${gW(r.totals.doughWeight)}`);
  }
  lines.push("");
  lines.push("METHOD");
  steps.forEach((st,i)=>lines.push(`${i+1}. ${st}`));
  lines.push("");
  lines.push("NOTES");
  lines.push("Dough is ready by condition, not just by clock: expanded, relaxed, slightly gassy, and easier to stretch.");
  lines.push("Use less topping on thin styles; use more bottom heat if the base is pale or soft.");
  return lines.join("\n");
}
function setExportStatus(msg){
  const el=$("exportStatus"); if(!el) return;
  el.textContent=msg;
  clearTimeout(setExportStatus.t);
  setExportStatus.t=setTimeout(()=>{el.textContent="";},2200);
}
async function copyRecipeText(){
  render();
  try{
    if(navigator.clipboard && window.isSecureContext){
      await navigator.clipboard.writeText(lastRecipeText);
    }else{
      const ta=document.createElement("textarea");
      ta.value=lastRecipeText; ta.style.position="fixed"; ta.style.left="-9999px";
      document.body.appendChild(ta); ta.focus(); ta.select(); document.execCommand("copy"); ta.remove();
    }
    setExportStatus("Copied");
  }catch(e){
    setExportStatus("Copy failed");
  }
}
function saveRecipeText(){
  render();
  const name=(STYLES[current].name+"-"+currentMethod+"-dough-recipe.txt").toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,"");
  const blob=new Blob([lastRecipeText],{type:"text/plain;charset=utf-8"});
  const a=document.createElement("a");
  a.href=URL.createObjectURL(blob); a.download=name; document.body.appendChild(a); a.click();
  setTimeout(()=>{URL.revokeObjectURL(a.href); a.remove();},0);
  setExportStatus("Saved");
}


function clearUVReveal(){
  document.querySelectorAll(".uv-secret").forEach(el=>{
    el.style.setProperty("--uv","0");
  });
}
function setUV(on){
  const active=!!on && document.documentElement.dataset.theme==="dark";
  document.documentElement.classList.toggle("uv-on",active);
  const btn=$("uvToggle");
  if(btn)btn.textContent=active?"UV Search Light: On":"UV Search Light";
  if(active){uvDirty=true;} else {clearUVReveal();}
}

/* --- UV reveal, optimised for mobile --- */
let _uvLast=null,_uvQueued=false;
let uvTargets=[],uvDirty=true;
function refreshUVTargets(){
  const nodes=document.querySelectorAll(".uv-secret");
  uvTargets.length=0;
  for(let i=0;i<nodes.length;i++){
    const el=nodes[i],r=el.getBoundingClientRect();
    // skip anything off-screen so we touch fewer nodes per frame
    if(r.bottom<-200||r.top>innerHeight+200){el.style.setProperty("--uv","0");continue;}
    uvTargets.push({el,l:r.left,t:r.top,rt:r.right,b:r.bottom});
  }
  uvDirty=false;
}
function _uvApply(){
  _uvQueued=false;
  const e=_uvLast; if(!e)return;
  const root=document.documentElement;
  const light=$("uvLight");
  // transform-only move: composited, no layout/paint thrash
  if(light)light.style.transform=`translate3d(${e.clientX}px,${e.clientY}px,0) translate(-50%,-50%)`;
  if(!root.classList.contains("uv-on")||root.dataset.theme!=="dark")return;
  if(uvDirty)refreshUVTargets();          // measure rarely, read cache every frame
  const inner=90,outer=190,span=outer-inner;
  const x=e.clientX,y=e.clientY;
  for(let i=0;i<uvTargets.length;i++){
    const o=uvTargets[i];
    const dx=Math.max(o.l-x,0,x-o.rt);
    const dy=Math.max(o.t-y,0,y-o.b);
    const d=Math.sqrt(dx*dx+dy*dy);
    let t=d<=inner?1:(d0)t=t*t*(3-2*t);              // smoothstep falloff
    o.el.style.setProperty("--uv",t.toFixed(3));
  }
}
function moveUV(e){
  // PointerEvent covers mouse + touch-drag; store coords, do the work in one rAF
  _uvLast=e;
  if(!_uvQueued){_uvQueued=true;requestAnimationFrame(_uvApply);}
}
function markUVDirty(){uvDirty=true;}

