let prevIng={};
let lastDevs=[]; // most recent set of "outside recommendation" deviations, for the exports
// flag where the user's value sits outside our recommendation: highlight the rec at the control, and return the list for the recipe
function checkDivergences(r){
  const s=STYLES[current], devs=[];
  const setD=(recId,on)=>{const el=$(recId); if(!el)return; const b=el.closest(".rec"); if(b)b.classList.toggle("diverged",!!on);};
  const fmt=(val,t)=> t==="pct"?fmtPct(val): t==="hrs"?(r1(val)+" hrs"): t==="temp"?tF(val): t==="wt"?(wNum(val)+" "+wtLabel()): String(val);
  const v=id=>{const el=$(id); return el&&el.value!==""?Number(el.value):null;};
  const single=(recId,label,user,rec,t,eps=null)=>{
    if(user==null||isNaN(user)){setD(recId,false);return;}
    // ±3% of the recommended value, floored at 0.5 so small/zero recs still get a usable band.
    // (A flat absolute tolerance can't fit hydration ~60 and salt ~2.5 at once — proportional scales to each field.)
    const tol = (eps==null) ? Math.max(Math.abs(rec)*0.03, 0.5) : eps;
    const d=Math.abs(user-rec)>tol; setD(recId,d);
    if(d) devs.push({label,you:fmt(user,t),rec:fmt(rec,t)});
  };
  const range=(recId,label,user,lo,hi,t)=>{
    if(user==null||isNaN(user)){setD(recId,false);return;}
    const d=(userhi+0.01); setD(recId,d);
    if(d) devs.push({label,you:fmt(user,t),rec:fmt(lo,t)+"–"+fmt(hi,t)});
  };
  single("hydrationRec","Hydration",v("hydration"),recHydrationFor(s.hydration,flourProteinVal()),"pct");
  single("mainYeastRec","Yeast",v("mainYeast"),r.mainYeastRec,"pct",Math.max(r.mainYeastRec*0.25,0.02));
  single("saltRec","Salt",v("salt"),s.salt,"pct");
  single("oilRec","Oil",v("oil"),s.oil,"pct");
  single("sugarRec",($("sugarLabel")&&/honey/i.test($("sugarLabel").textContent))?"Honey":"Sugar",v("sugar"),s.sugar,"pct");
  single("milkPowderRec","Milk powder",v("milkPowder"),s.milkPowder||0,"pct");
  if(r.loss) single("lossAllowRec","Dough loss allowance",r.loss.val,r.loss.rec,"pct");
  if(r.vinegar&&r.vinegar.on) single("vinegarRec","Vinegar",r.vinegar.pct,r.vinegar.rec,"pct");
  range("totalRec","Total time",v("totalHours"),r.timeRange.min,r.timeRange.max,"hrs");
  // (individual bulk/ball/preferment recs are derived from the total, so comparing them is circular — total time is the meaningful signal)
  if(currentMethod==="trad"){
    const pf=PREFERMENTS[$("preferment").value];
    single("poolishPctRec",($("preferment").value==="biga"?"Biga":"Poolish")+" amount",v("poolishPct"),pf.flourPct,"pct");
    single("prefHydrationRec","Preferment hydration",v("prefHydration"),pf.hydration,"pct");
  }
  // bake temperature: only flag if HOTTER than the style wants — below ideal is normal for home ovens and is explained separately
  const ot=tempToBase($("oven").value);
  if(Number.isFinite(ot) && ot>s.bake.max+1){ setD("ovenRec",true); devs.push({label:"Bake temperature",you:tF(ot),rec:tF(s.bake.idealMin)+"–"+tF(s.bake.max)}); } else setD("ovenRec",false);
  // dough ball weight (only if set)
  if($("ballWeight")&&$("ballWeight").value!==""){const bw=wtToBase($("ballWeight").value); single("ballWeightRec","Dough weight per "+styleUnitName(current,false),Number.isFinite(bw)?bw:null,r.totals.ballWeightRec,"wt",3);}
  else setD("ballWeightRec",false);
  return devs;
}
// Section 6 oven/surface notes + warning + base-field visibility
function syncBakeUI(){
  const ovenType=$("ovenType")?$("ovenType").value:"home";
  const base=$("bakeBase")?$("bakeBase").value:"steel";
  const g=bakeGuidance(current,ovenType,base);
  if($("ovenTypeNote"))$("ovenTypeNote").textContent=g.ovenNote;
  if($("bakeBaseNote"))$("bakeBaseNote").textContent=g.baseNote;
  if($("warnBake"))$("warnBake").innerHTML=g.warn?`
!${g.warn}`:"";
  if($("bakeBaseField"))$("bakeBaseField").style.display=PAN_STYLES.includes(current)?"none":"";
}
// distribute warning flags to inline slots at the controls that trigger them
function renderInlineFlags(flags){
  // Manual timing still receives safety and feasibility warnings; only the values remain editable.
  const slots={yeast:$("warnYeast"),preferment:$("warnPreferment"),bulk:$("warnBulk"),cold:$("warnColdMirror")||$("warnCold"),ball:$("warnBall"),time:$("warnTime"),ferment:$("warnFerment"),vinegar:$("warnVinegar"),fallback:$("flagNotes")};
  Object.values(slots).forEach(el=>{if(el)el.innerHTML="";});
  const mkNote=(f)=>{const d=document.createElement("div");d.className="note "+(f.level==="adjust"?"adjust":"warn");d.innerHTML=`!${f.msg}`;return d;};
  (flags||[]).forEach(f=>{
    const wheres=Array.isArray(f.where)?f.where:[f.where];
    let placed=false;
    wheres.forEach(wk=>{const el=slots[wk]; if(!el)return; placed=true; el.appendChild(mkNote(f));});
    if(!placed && slots.fallback) slots.fallback.appendChild(mkNote(f));
  });
}
function ingList(container, items){
  const ul=document.createElement("ul");ul.className="ilist";
  // column header
  const head=document.createElement("li");head.className="ilist-head";
  head.innerHTML=`Ingredientbaker's %weight`;
  ul.appendChild(head);
  items.forEach(([label,val,key,pct,fmt])=>{
    if(val==null)return;
    const li=document.createElement("li");
    const flash = prevIng[key]!==undefined && prevIng[key]!==val;
    if(flash)li.className="flash";
    const pctTxt = (pct==null||pct==="") ? "" : `${pct}%`;
    li.innerHTML=`${label}${pctTxt}${(fmt||wNum)(val)}${wtLabel()}`;
    ul.appendChild(li);prevIng[key]=val;
  });
  container.appendChild(ul);
}


function esc(s){return String(s==null?"":s).replace(/[&<>"]/g,c=>({"&":"&","<":"<",">":">","\"":"""}[c]));}
function renderGuidance(styleKey){
  const g=STYLE_GUIDANCE[styleKey],cue=STYLE_READY_CUES[styleKey]||STYLE_READY_CUES.ny;
  const rows=[...COMMON_TROUBLESHOOTING,...(STYLE_TROUBLESHOOTING[styleKey]||[])];
  const troubleRows=rows.map(([p,c])=>`
${esc(p)}${esc(c)}`).join("");
  const flourText=styleKey==="softbread"
    ? "Moderate bread flour gives enough structure without making the crumb unnecessarily chewy. Very strong flour may need a little more water; weak flour may need less."
    : styleKey==="ciabatta"||styleKey==="roman"||styleKey==="focaccia"
    ? "This wet dough relies on flour strength. If it spreads, tears or cannot retain gas after folds, lower hydration or use stronger flour rather than adding flour blindly during handling."
    : "Flour strength sets how much water and fermentation the dough can tolerate. If it spreads, tears or collapses, shorten the ferment, lower hydration or use stronger flour.";
  return `


How to judge it
${esc(cue)} The displayed time is a planning range; the physical condition decides when to continue.


Best used for

${esc(g.best)}
${esc(g.topping)}


Flour and structure
${esc(flourText)}


Quick fixes
${troubleRows}`;
}
function updatePrintRecipe(r,steps){
  const yt=r.yeastTypeName.toLowerCase();
  let html=`
${esc(r.styleName)} dough
${esc(r.methodName)} · ${esc(recipeFormatText(r))} · total dough ${gW(r.totals.doughWeight)} · fermentation ${fmtHShort(r.totalTime)}`;
  if(lastDevs&&lastDevs.length){
    html+=`
Outside our recommendations${lastDevs.map(d=>`
${esc(d.label)}: you set ${esc(d.you)}, recommended ${esc(d.rec)}`).join("")}
All fine — the further you move from the recommended values, the less predictable the result becomes.`;
  }
  html+=`
Ingredients`;
  if(r.isTrad){
    const pf=r.preferment;
    html+=`
Step 1 — ${esc(pf.name)}
Ferment ${esc(fmtH(pf.hours))} at room temperature · ${pf.hydration}% hydration
Flour${gW(pf.flour)}
Water${gW(pf.water)}
Yeast (${esc(yt)})${gWy(pf.yeast)}`;
    html+=`
Step 2 — Final dough
Add to the ${esc(pf.name.toLowerCase())}`;
    if(r.stageAmounts.flour.final>0)html+=`
Flour${gW(r.stageAmounts.flour.final)}`;
    html+=`
Water${gW(r.stageAmounts.water.final)}
Salt${gW(r.ingredients.salt)}`;
    if(r.stageAmounts.finalYeast>0.04)html+=`
Finishing yeast (${esc(yt)})${gWy(r.stageAmounts.finalYeast)}`;
    if(r.ingredients.oil!=null)html+=`
Oil${gW(r.ingredients.oil)}`;
    if(r.ingredients.sugar!=null)html+=`
Sugar${gW(r.ingredients.sugar)}`;
    if(r.ingredients.milkPowder!=null)html+=`
Milk powder${gW(r.ingredients.milkPowder)}`;
    html+=``;
  }else{
    html+=`
Flour${gW(r.ingredients.flour)}
Water${gW(r.ingredients.water)}${r.ingredients.vinegar!=null?`
Vinegar${gW(r.ingredients.vinegar)}`:""}
Salt${gW(r.ingredients.salt)}
Yeast (${esc(yt)})${gWy(r.ingredients.yeast)}`;
    if(r.ingredients.oil!=null)html+=`
Oil${gW(r.ingredients.oil)}`;
    if(r.ingredients.sugar!=null)html+=`
Sugar${gW(r.ingredients.sugar)}`;
    if(r.ingredients.milkPowder!=null)html+=`
Milk powder${gW(r.ingredients.milkPowder)}`;
    html+=``;
  }
  if(r.totals.lossGrams>0){
    html+=`
Dough totals
Total mixed (gross)${gW(r.totals.grossDough)}
Less ~${r.loss.val}% lost to bowl & hands−${gW(r.totals.lossGrams)}
Working dough${gW(r.totals.doughWeight)}`;
  }
  html+=`
Method${steps.map(st=>`
${esc(st)}`).join("")}`;
  html+=`
Notes
Dough is ready by condition, not just by clock: expanded, relaxed, slightly gassy, and easier to stretch. Use less topping on thin styles; use more bottom heat if the base is pale or soft.`;
  $("printRecipe").innerHTML=html;
}


function applyUnitLabels(){
  document.querySelectorAll('.len-unit').forEach(e=>e.textContent=UNIT.len);
  document.querySelectorAll('.wt-unit').forEach(e=>e.textContent=UNIT.wt);
  document.querySelectorAll('.temp-unit').forEach(e=>e.textContent='°'+UNIT.temp);
  document.querySelectorAll('[data-unit="len"]').forEach(b=>b.classList.toggle('on',b.dataset.val===UNIT.len));
  document.querySelectorAll('[data-unit="wt"]').forEach(b=>b.classList.toggle('on',b.dataset.val===UNIT.wt));
  document.querySelectorAll('[data-unit="temp"]').forEach(b=>b.classList.toggle('on',b.dataset.val===UNIT.temp));

  const dimensional=[['diameter',6,0.5],['panL',4,0.5],['panW',4,0.5],['panDepth',0.5,0.25]];
  dimensional.forEach(([id,minIn,stepIn])=>{const el=$(id);if(!el)return;el.min=String(fmtLenNum(minIn));el.step=UNIT.len==='cm'?'0.1':String(stepIn);});
  const bw=$('ballWeight');if(bw){bw.min=UNIT.wt==='oz'?'0.04':'1';bw.step=UNIT.wt==='oz'?'0.01':'1';}
  const tempBounds=[['ambient',1,40],['fridgeTemp',1,10],['oven',150,550]];
  tempBounds.forEach(([id,minC,maxC])=>{const el=$(id);if(!el)return;el.min=String(Math.round(tempFromBase(minC)));el.max=String(Math.round(tempFromBase(maxC)));el.step=id==='oven'?(UNIT.temp==='F'?'9':'5'):'1';});
}
function setUnit(kind,val){
  if(UNIT[kind]===val) return;
  if(kind==='len'){
    const ids=['diameter','panL','panW','panDepth'];
    const base=ids.map(id=>{const el=$(id); return el? lenToBase(el.value):null;});
    UNIT.len=val;
    ids.forEach((id,i)=>{const el=$(id); if(el&&base[i]!=null&&Number.isFinite(base[i])) el.value=String(fmtLenNum(base[i]));});
    // refresh rec labels that carry a unit
    const s=STYLES[current];
    if(userShape==='round'&&$('diameterRec')) $('diameterRec').textContent=fmtLenNum(roundDefIn(s))+' '+lenLabel();
    if(s.hasDepth&&$('panDepthRec')) $('panDepthRec').textContent=fmtLenNum(s.depthMin)+'–'+fmtLenNum(s.depthMax)+' '+lenLabel();
  } else if(kind==='temp'){
    const el=$('oven'); const c=el?tempToBase(el.value):null;
    const amb=$('ambient'); const ac=amb?tempToBase(amb.value):null;
    const fridge=$('fridgeTemp'); const fc=fridge?tempToBase(fridge.value):null;
    UNIT.temp=val;
    if(el&&c!=null&&Number.isFinite(c))el.value=String(Math.round(tempFromBase(c)));
    if(amb&&ac!=null&&Number.isFinite(ac))amb.value=String(Math.round(tempFromBase(ac)));
    if(fridge&&fc!=null&&Number.isFinite(fc))fridge.value=String(Math.round(tempFromBase(fc)));
    const s=STYLES[current];
    if($('ovenRec')) $('ovenRec').textContent=tF(s.bake.idealMin)+'–'+tF(s.bake.max);
    if($('ambientRec')) $('ambientRec').textContent=tF(AMBIENT_BASELINE_C);
  } else {
    const el=$('ballWeight'); const g= el? wtToBase(el.value):null;
    UNIT.wt=val;
    if(el&&g!=null&&Number.isFinite(g)) el.value=String(wNum(g));
  }
  applyUnitLabels();
  render();
}
function setSchedMode(mode){
  schedMode=mode;
  const needsAnchor=(mode==='startAt'||mode==='readyBy');
  const wrap=$('schedAnchorWrap'); if(wrap) wrap.style.display=needsAnchor?'':'none';
  document.querySelectorAll('[data-sched]').forEach(b=>b.classList.toggle('on',b.dataset.sched===mode));
  const lbl=$('schedAnchorLabel'); if(lbl) lbl.textContent = mode==='readyBy'?'Finished baking by' : 'Start at';
  render();
}
function readAnchor(){
  const el=$('schedAnchor'); if(!el||!el.value){schedAnchor=null;return;}
  const t=new Date(el.value).getTime(); schedAnchor=Number.isFinite(t)?t:null;
}

function recipeFormatText(r){
  if(STYLES[r.styleKey].sizing==="weight"){
    let unit=r.styleKey==="baguette"?"baguette":r.styleKey==="ciabatta"?"loaf":r.styleKey==="softbread"?(r.breadFormat==="rolls"?"roll":"loaf"):"portion";
    if(r.quantity!==1)unit=(unit==="loaf"?"loaves":unit+"s");
    return `${r.quantity} × ${gW(r.totals.ballWeight)} ${unit}`;
  }
  return r.shape==="round"?`${r.quantity} × ${fmtLenNum(r.size.diameter)}${lenLabel()} pizza`:`${r.quantity} × ${fmtLenNum(r.size.length)}×${fmtLenNum(r.size.width)}${r.size.depth!=null?"×"+fmtLenNum(r.size.depth):""}${lenLabel()} pan`;
}
function render(){
  readAnchor();   // refresh wall-clock anchor before calculate() builds the timestamped method
  const s=STYLES[current];
  const r=calculate(buildOpts());
  // yeast field + its "starting point" track the ACTUAL final-ferment time, so the auto-adjustment to the
  // chosen time is visible (and matches what the recipe uses). The rec hint always shows the time-appropriate
  // dose — the same number the over-proof warning suggests — even when the user has hand-set the yeast.
  if($("mainYeastRec")) $("mainYeastRec").textContent = r.mainYeastRange[0]+"–"+r.mainYeastRange[1]+"%";
  { const _cust=((typeof currentTimeframe==="undefined") || !currentTimeframe);
    document.querySelectorAll('.rec').forEach(el=>{el.style.display=_cust?'none':'';}); }
  if(!yeastTouched.main && $("mainYeast")) $("mainYeast").value = r.mainYeastPct;

  // C1: keep the Section 3 preferment-time mirror in lock-step with sPreferment (don't fight the user mid-type)
  if($("sPrefermentMirror")){
    if(document.activeElement!==$("sPrefermentMirror")) $("sPrefermentMirror").value=$("sPreferment").value;
    if($("sPrefermentMirrorRec")&&$("sPrefermentRec")) $("sPrefermentMirrorRec").textContent=$("sPrefermentRec").textContent;
  }

  // dough ball weight: show recommendation, pre-fill unless the user has edited it
  if($("ballWeightRec")){
    $("ballWeightRec").textContent=wNum(r.totals.ballWeightRec)+" "+wtLabel();
    if(!ballTouched) $("ballWeight").value=wNum(r.totals.ballWeightRec);
    if($("ballWeightLabel")) $("ballWeightLabel").textContent="Dough weight per "+styleUnitName(current,false);
  }

  // Batch-yield line. Pizza/pan styles use a rough dough-per-person guide; loaves report their actual output.
  if($("feedsText")){
    const net=r.totals.doughWeight;
    if(STYLES[current].sizing==="weight"){
      const units=styleUnitName(current,r.quantity!==1);
      $("feedsText").innerHTML=`Makes ${r.quantity} ${units} at ${gW(r.totals.ballWeight)} each — ${gW(net)} working dough.`;
    }else{
      const ppl=net/250; let lo,hi;
      if(ppl-Math.floor(ppl)>=0.5){hi=Math.ceil(ppl);lo=hi-1;}else{lo=Math.floor(ppl);hi=lo+1;}
      if(lo<1)lo=1;if(hi<lo)hi=lo;
      const range=lo===hi?`${hi}`:`${lo} to ${hi}`;
      $("feedsText").innerHTML=`${gW(net)} of dough should feed about ${range} ${hi===1?"person":"people"}.`;
    }
  }

  $("recipeStyle").textContent=r.styleName;
  $("tDough").textContent=gW(r.totals.doughWeight);
  if($("tDoughK"))$("tDoughK").textContent="total dough";
  $("tTime").textContent=r.timeRange.supported?fmtHRangeShort(r.timeRange):"Not reliable";
  $("tBall").textContent=gW(r.totals.ballWeight);
  $("tBallK").textContent="per "+styleUnitName(current,false);
  if($("finalProofLabel"))$("finalProofLabel").textContent=PAN_STYLES.includes(current)?"Pan proof":(STYLES[current].category==="bread"?"Final proof":"Ball ferment");

  $("methodTag").textContent=r.methodName+" · "+(r.isCold?"Refrigerated · ":"")+recipeFormatText(r)+(r.isTrad?" · "+r.preferment.name:"");
  renderRecipeUVSecret(r);

  // ---- RECIPE SECTIONS (baker's % shown inline) ----
  const rs=$("recipeSections");rs.innerHTML="";
  const yt=r.yeastTypeName.toLowerCase();
  const T=r.pctTable;
  const totalFlour=r.totals.flour||1;
  const pctOfTotal=g=>r1((g/totalFlour)*100);
  if(r.isTrad){
    const pf=r.preferment;
    // Section 1: preferment — percentages are relative to the preferment's own flour
    const s1=document.createElement("div");s1.className="rsection";
    s1.innerHTML=`
Step 1 — ${pf.name}
ferment ${fmtHRange(pf.timeRange)}${appMode==="expert"?` · percentages are of the ${pf.name.toLowerCase()}'s own flour`:""}`;
    rs.appendChild(s1);
    ingList(s1,[["Flour",pf.flour,"p_flour",100],["Water",pf.water,"p_water",pf.hydration],["Yeast ("+yt+")",pf.yeast,"p_yeast",pf.yeastPct,wNumY]]);
    // Section 2: final dough — percentages are of the TOTAL flour
    const s2=document.createElement("div");s2.className="rsection";
    s2.innerHTML=`
Step 2 — Final dough
add to the ${pf.name.toLowerCase()}${appMode==="expert"?" · percentages are of the total flour":""}`;
    rs.appendChild(s2);
    const finalItems=[];
    if(r.stageAmounts.flour.final>0)finalItems.push(["Flour",r.stageAmounts.flour.final,"f_flour",r1(100-pf.flourPct)]);
    finalItems.push(["Water",r.stageAmounts.water.final,"f_water",pctOfTotal(r.stageAmounts.water.final)]);
    finalItems.push(["Salt",r.ingredients.salt,"f_salt",T.salt]);
    if(r.stageAmounts.finalYeast>0.04)finalItems.push(["Finishing yeast ("+yt+")",r.stageAmounts.finalYeast,"f_yeast",r.mainYeastPct,wNumY]);
    if(r.ingredients.oil!=null)finalItems.push(["Oil",r.ingredients.oil,"f_oil",T.oil]);
    if(r.ingredients.sugar!=null)finalItems.push(["Sugar",r.ingredients.sugar,"f_sugar",T.sugar]);
    if(r.ingredients.milkPowder!=null)finalItems.push(["Milk powder",r.ingredients.milkPowder,"f_milk",T.milkPowder]);
    ingList(s2,finalItems);
  } else {
    const sec=document.createElement("div");sec.className="rsection";
    sec.innerHTML=`
Ingredients
${appMode==="expert"?"percentages are baker's % (of total flour)":"weigh each ingredient before mixing"} · yeast starting range ${r.mainYeastRange[0]}–${r.mainYeastRange[1]}%`;
    rs.appendChild(sec);
    ingList(sec,[
      ["Flour",r.ingredients.flour,"flour",100],
      ["Water",r.ingredients.water,"water",T.water],
      ["Vinegar",r.ingredients.vinegar,"vinegar",T.vinegar],
      ["Salt",r.ingredients.salt,"salt",T.salt],
      [(appMode==="easy"?"Yeast — starting point (":"Yeast (")+yt+")",r.ingredients.yeast,"yeast",r.mainYeastPct,wNumY],
      ["Oil",r.ingredients.oil,"oil",T.oil],
      ["Sugar",r.ingredients.sugar,"sugar",T.sugar],
      ["Milk powder",r.ingredients.milkPowder,"milkPowder",T.milkPowder]
    ]);
  }

  // ---- DOUGH TOTALS (gross mixed → less loss → working) ----
  {
    const u=wtLabel();
    const row=(label,val,opts={})=>{
      const strong=opts.strong?"font-weight:700;":"";
      const sub=opts.sub?"color:var(--ink-soft);":"";
      const sign=opts.sign||"";
      const top=opts.top?"border-top:1px solid var(--line);":"";
      return `
${esc(label)}${sign}${wNum(val)}${u}`;
    };
    const wrap=document.createElement("div");wrap.className="rsection";
    let inner=`
Dough totals`;
    if(r.totals.lossGrams>0){
      inner+=row("Total mixed (gross weight)",r.totals.grossDough);
      inner+=row(`Less ~${r.loss.val}% lost to bowl & hands`,r.totals.lossGrams,{sub:true,sign:"−"});
      inner+=row("Working dough (what you portion)",r.totals.doughWeight,{strong:true,top:true});
    } else {
      inner+=row("Working dough (what you portion)",r.totals.doughWeight,{strong:true});
    }
    inner+=``;
    wrap.innerHTML=inner;
    rs.appendChild(wrap);
  }

  // calc total time
  $("calcTotal").innerHTML=r.timeRange.supported?"Expected fermentation window: "+fmtHRangeShort(r.timeRange)+". The stage boxes use central planning values; the dough-readiness cues decide when to move on.":"Automatic timing is not reliable at this temperature. Change the temperature or use the dough-readiness cues without treating the displayed stage values as a schedule.";


  // schedule timestamps now live inline in the method steps; keep the old block hidden
  const schedEl=$("scheduleBlock");
  if(schedEl){ schedEl.innerHTML=""; schedEl.style.display="none"; }

  // method
  const steps=mode==="expanded"?r.methodExpanded:r.method;
  const me=$("method-steps");me.innerHTML="";
  const recipeSecret=getRecipeUVSecret(r);
  steps.forEach((st,i)=>{const li=document.createElement("li");li.innerHTML=esc(st)+(i===0?uvMarker(recipeSecret):"");me.appendChild(li);});

  // bake note
  const chk=checkOven(current,tempToBase($("oven").value));const bn=$("bakeNote");
  if(chk){bn.style.display="flex";bn.className="note "+chk.level;const icon=chk.level==="ok"?"✓":chk.level==="warn"?"!":"≈";bn.innerHTML=`${icon}${chk.message}`;}else{bn.style.display="none";}

  // oven/surface guidance (Section 6 notes + warning) and the prominent bake line
  syncBakeUI();
  if($("bakeSummary")){
    const g=bakeGuidance(current,r.bakeInfo.ovenType,r.bakeInfo.base);
    const surf=PAN_STYLES.includes(current)?(current==="softbread"?"in its tin or tray":"in its pan"):("on "+(BASES[r.bakeInfo.base]?BASES[r.bakeInfo.base].name:"a steel"));
    let h=`
Bake: about ${r.bakeInfo.timeStr} at ${tF(r.bakeInfo.tempC)} ${surf}.`;
    if(g.suitability) h+=`
${g.suitability}`;
    if(g.setup) h+=`
Setup: ${g.setup}`;
    $("bakeSummary").innerHTML=h;
  }

  // red flags → rendered inline at the control that triggered them (not buried at the recipe end)
  renderInlineFlags(r.flags);
  // divergence: highlight diverged recommendations + list boundary breaches in the recipe
  const devs=checkDivergences(r);
  lastDevs=devs;
  if($("recipeDeviations")){
    if(devs.length){
      let h='

Outside our recommendations';
      devs.forEach(d=>h+=`
${d.label}: you set ${d.you}, recommended ${d.rec}`);
      h+='
All fine — this calculator is built to be pushed. Treat these as a map, not a rule: the further you move from the recommended values, the less predictable the result becomes.';
      $("recipeDeviations").innerHTML=h;
    } else $("recipeDeviations").innerHTML="";
  }
  // mixing-water guidance under the ambient input
  if($("waterTempLine") && r.water){
    let _wl=r.water.feasible
      ? `Mixing water: aim for about ${tF(r.water.tempC)} — ${r.water.cue}. Target dough temperature about ${tF(r.water.ddt)}.`
      : `Practical water limit: about ${tF(r.water.tempC)} — ${r.water.cue}. This would still produce roughly ${tF(r.water.predictedDoughTemp)}, not the ${tF(r.water.ddt)} target. ${r.water.message}`;
    if(r.water.hotMachine) _wl+=` A ${mixMode} mixer adds friction heat fast in a kitchen this warm — start with the coldest, even iced, water and stop kneading the moment the dough nears ${tF(r.water.ddt)}.`;
    $("waterTempLine").innerHTML=_wl;
  }

  // practical guidance
  const nb=$("notesBlock");
  nb.innerHTML=renderGuidance(current);
  nb.hidden=!$("recipeHelp").classList.contains("open");
  lastRecipeText=recipeText(r,steps);
  updatePrintRecipe(r,steps);
  uvDirty=true;   // secret spans were re-created; remeasure on next sweep
}
function fmtHShort(h){const m=Math.round(Number(h)*60);if(m<60)return m+"m";const hr=Math.floor(m/60),mn=m%60;return hr+"h"+(mn?" "+mn+"m":"");}
function fmtHRangeShort(range){if(!range)return"";const a=range.min!=null?range.min:range[0],b=range.max!=null?range.max:range[1];return Math.abs(a-b)<0.01?fmtHShort(a):fmtHShort(a)+"–"+fmtHShort(b);}

