// collapsible input sections — click the title bar to fold a section down to its heading
document.querySelectorAll('.section-box').forEach(box=>{
  const label=box.querySelector('.sec-label');
  if(!label) return;
  const chev=document.createElement('span');
  chev.className='sec-toggle'; chev.textContent='\u25BE'; chev.setAttribute('aria-hidden','true');
  label.appendChild(chev);
  label.setAttribute('title','Click to collapse or expand this section');
  label.addEventListener('click',()=>box.classList.toggle('collapsed'));
  // C3: input sections 2–6 start collapsed (recipe folds have no sec-num, so they stay open)
  const numEl=box.querySelector('.sec-num');
  const secN=numEl?parseInt(numEl.textContent,10):0;
  if(secN>=2&&secN<=6) box.classList.add('collapsed');
});

// C1: collapsible Q&A section (collapsed by default)
{ const fh=$('faqHead'), fp=$('faqPanel');
  if(fh&&fp){
    const toggleFaq=()=>{ const collapsed=fp.classList.toggle('collapsed'); fh.setAttribute('aria-expanded', String(!collapsed)); };
    fh.addEventListener('click',toggleFaq);
    fh.addEventListener('keydown',e=>{ if(e.key==='Enter'||e.key===' '){ e.preventDefault(); toggleFaq(); } });
  }
}

/* ---- FAQ (Wave 4d / 4.10): common questions, short answer + expandable detail ---- */
 const FAQ=[
  {q:"Why grams? Can't I just use cups?",
   s:"Use a scale. Dough formulas are sensitive to small changes, and volume measures are not repeatable enough.",
   l:["The amount of flour in a cup changes with the scoop, packing and flour itself. That changes the true hydration even when the written recipe is unchanged.",
      "Grams and baker's percentages let the recipe scale cleanly and make your next batch comparable with the last one. A digital scale that reads to 1 g is suitable for the main ingredients; very small preferment doses may require a 0.01 g scale or a larger batch."]},
  {q:"Does the flour I use really matter?",
   s:"Yes. Flour strength determines how much water, mixing and fermentation the dough can tolerate.",
   l:["Protein percentage is a useful first indicator, although two flours with the same printed protein can still behave differently. Stronger flour generally supports more water and longer fermentation; weaker flour often needs lower hydration or a shorter schedule.",
      "In Easy mode, choose the closest flour type. In Expert mode, enter the printed protein percentage and treat the hydration recommendation as a starting point. Self-raising and cake flour are not suitable substitutes for the yeasted doughs in this calculator."]},
  {q:"My dough is too sticky to handle — did I get it wrong?",
   s:"Not necessarily. Wet dough should be tacky; the real question is whether it develops structure after mixing, resting and folds.",
   l:["Use wet hands and a scraper, keep the dough reasonably cool and give it the development described in the method. Do not keep dusting flour into the dough during every handling step, because that changes the formula.",
      "If it remains a smear with no strength after proper development, the flour may not support the selected hydration, the dough may be too warm or it may be over-fermented. Lower hydration slightly on the next batch rather than fighting it with unmeasured flour or oil."]},
  {q:"What is the difference between bulk fermentation and final proof?",
   s:"Bulk develops the mixed dough as one mass; final proof happens after it has been divided, shaped or placed in the pan.",
   l:["Bulk fermentation builds gas, flavour and dough structure before final shaping. Folds, when required, happen early in this stage.",
      "Final proof relaxes and aerates the shaped dough. For round pizza it is the ball ferment; for Detroit, Roman and focaccia it happens in the pan; for baguette, ciabatta, loaves and rolls it happens after final shaping."]},
  {q:"How long should I ferment or proof the dough?",
   s:"Use the displayed range for planning, then continue when the style-specific readiness cue is met.",
   l:["Temperature, yeast dose, flour, salt, enrichment and dough mass all shift the clock. That is why Doughborough shows a range rather than pretending one minute is universally correct.",
      "Do not apply one doubling rule to every style. Pizza balls may be only lightly puffy; a loaf may rise near the tin rim; ciabatta should become aerated without being allowed to weaken and collapse."]},
  {q:"How do I know when the dough is actually ready?",
   s:"Read the cue printed in the method and Help panel; no single poke test works equally well for every dough.",
   l:["Look for the combination required by the style: expansion, gas, relaxation and retained strength. A pizza ball must stretch without snapping back; baguettes must feel lighter but still hold tension; focaccia should be puffy and jiggly.",
      "A gentle press is useful on shaped loaves and balls: fast recovery usually means more proof is needed, while no recovery plus a fragile surface suggests the dough is near or beyond its limit. Very wet doughs are better judged by gas, jiggle and structure than by poking alone."]},
  {q:"Why didn't my dough rise?",
   s:"First check temperature and time; then check whether the yeast was present, alive and measured correctly.",
   l:["A cold or very low-yeast dough can appear inactive for hours without being dead. Move it to a modestly warmer place and look for gas before discarding it. Do not expose it to strong heat in an attempt to force it.",
      "If there is still no activity, likely causes include omitted or expired yeast, water that was excessively hot, a serious measuring error or unusually high salt. Active dry yeast also needs proper rehydration. Machine mixing can overheat dough, which is why the calculator reports a water-temperature feasibility warning in hot kitchens."]},
  {q:"How do I stretch or shape it without tearing?",
   s:"Work out whether the dough is tight or weak: tight dough needs rest; weak dough needs better development, less water or less fermentation.",
   l:["Dough that snaps back and tears under tension is usually under-relaxed. Cover it and wait. Dough that stretches into a thin weak sheet, smears or cannot hold shape may be under-developed, over-fermented, too warm or too wet for the flour.",
      "Use the shaping method for the selected style. Preserve the rim on Neapolitan, avoid degassing ciabatta, create surface tension on baguettes and soft bread, and never force wet pan dough into the corners when a rest will do the work."]},
  {q:"Can I make this faster?",
   s:"Yes. Choose ASAP or Same day; the calculator shortens the plan and adjusts the yeast within its supported limits.",
   l:["A faster dough usually uses a direct method and more yeast, trading some fermentation development for speed. It can still be a good dough, but it has less margin for delay and temperature error.",
      "Do not shorten below the warning limits. If the chosen style cannot hydrate, relax and proof in the available window, select a different schedule rather than treating yeast as a substitute for physical dough development."]},
  {q:"How does refrigerator fermentation work here?",
   s:"It is a separate three-part plan: a warm start, a cold hold that includes cooling lag, and a warm final proof.",
   l:["Dough does not become refrigerator-cold instantly. Doughborough integrates the faster early fermentation while the centre cools, then the slower refrigerated hold.",
      "A named timeframe such as Two to three days is your available-duration constraint; the same cold-exposure engine then calculates the yeast and stage warnings. The range is deliberately broad because fridge cycling, dough mass and container shape change the result. Judge final readiness after the dough has warmed and relaxed."]},
  {q:"How do I know when a poolish or biga is ready?",
   s:"Use it at peak maturity, not merely when the timer ends.",
   l:["A poolish should be well expanded and full of bubbles, with its surface at peak or just beginning to level. A fully collapsed, sharply alcoholic poolish has gone too far.",
      "A biga should be expanded and aerated inside, with a domed or lightly cracked surface and a clean sweet, wheaty aroma. It remains stiff; it should not look like a liquid poolish. The method prints the temperature-adjusted window for both."]},
  {q:"Do I need a pizza stone or steel?",
   s:"No, but a fully preheated heavy surface is the largest practical upgrade for thin pizza in a home oven.",
   l:["Steel transfers heat into the base aggressively and is especially useful in lower-temperature home ovens. Stone heats less aggressively and is the normal floor in a pizza oven. Both require a complete preheat.",
      "Detroit, Roman al taglio, focaccia and soft bread bake in their own pans or tins. Ciabatta and baguette benefit from a preheated stone or heavy tray plus steam. A steel can work, but its aggressive bottom heat needs watching; they do not require a dedicated pizza oven."]},
  {q:"What temperature should I bake at?",
   s:"Use the temperature shown for the selected style and enter the temperature your oven can actually maintain.",
   l:["Thin pizza uses high heat and short baking to set the crust before it dries. Thick pan pizza and bread require more moderate heat so the centre cooks before the surface burns.",
      "The displayed time is an estimate. Judge colour, base condition and internal doneness. When your oven is below the recommended range, longer baking can dry the product before it browns, so changing the heat source or baking surface may matter more than adding minutes."]},
  {q:"Why is my pizza base soggy?",
   s:"The usual causes are weak bottom heat, excessive wet topping, an under-set base or trapped steam after baking.",
   l:["Preheat the steel, stone or pan completely and keep sauce plus wet toppings proportionate to the dough. Roman tray pizza may need its base set before wet toppings are added.",
      "Remove pan pizza from the pan after a short rest and place finished pizza on a rack when practical. Leaving it flat on a board or sealed in a hot pan traps steam against the underside."]},
  {q:"Why do baguette and ciabatta need steam?",
   s:"Early steam keeps the surface flexible long enough for expansion and changes the finished crust.",
   l:["Use a covered baking setup or a preheated sturdy metal tray designed to receive boiling water. Keep clear of the steam and never pour water onto oven glass or directly onto the oven floor.",
      "Vent or remove the steam source for the final part of the bake so the crust can dry and become crisp. Steam is useful early; continuous heavy steam can leave the crust pale or leathery."]},
  {q:"Can I freeze the dough?",
   s:"Pizza balls and shaped rolls freeze reasonably well; delicate high-hydration lean dough is less predictable and is usually better baked first.",
   l:["For pizza, freeze well-covered portions after bulk fermentation and thaw them in the refrigerator before completing the warm final proof. For soft rolls, freeze shaped portions before final proof or freeze the baked rolls.",
      "Freezing does not simply pause every yeast cell without damage; activity may be reduced after thawing. Allow extra proofing time and judge the dough condition. Ciabatta and baguette are generally more reliable when baked, cooled and then frozen rather than frozen as raw shaped dough."]},
  {q:"Can I make pizza dough without commercial yeast?",
   s:"A sourdough starter can replace commercial yeast, but it needs a separate inoculation and fermentation model that this version does not calculate.",
   l:["Chemical raising agents can make a quick pizza-like flatbread, but they do not reproduce fermented dough structure or flavour. Eggs and gums also change the formula rather than replacing fermentation.",
      "Do not enter a sourdough starter as though it were instant yeast. Starter strength, flour and water contribution, acidity and inoculation percentage all need to be accounted for separately."]}
]

function renderFAQ(){
  const wrap=document.getElementById("faqList");
  if(!wrap) return;
  wrap.innerHTML=FAQ.map((it,i)=>{
    const longHtml=it.l.map(p=>`
${esc(p)}`).join("");
    return `
`+
      ``+
      `${i+1}. ${esc(it.q)}\u25BE`+
      `
${esc(it.s)}`+
      `
${longHtml}`+
    ``;
  }).join("");
  wrap.querySelectorAll(".faq-item").forEach(item=>{
    const btn=item.querySelector(".faq-q");
    btn.addEventListener("click",()=>{
      const open=item.classList.toggle("open");
      btn.setAttribute("aria-expanded",open?"true":"false");
    });
  });
}
renderFAQ();

// Apply links from the landing page. Unknown values fall back safely to Easy-mode defaults.
(function applyInitialUrlState(){
  const params=new URLSearchParams(window.location.search);
  const requestedStyle=params.get("style");
  const requestedMode=params.get("mode");
  const requestedFormat=params.get("format");
  if(requestedMode==="cold"){currentTimeframe="2-3day";fermentationMode="cold";}
  updateTimeframeUI();
  selectStyle(STYLES[requestedStyle]?requestedStyle:"neapolitan");
  if(requestedMode==="cold"){
    currentTimeframe="2-3day";fermentationMode="cold";
    updateTimeframeUI();syncFermentationUI();refreshStageDefaults();render();
  }
  if(current==="softbread"&&requestedFormat==="rolls")setBreadFormat("rolls");
})();
